     1→import { randomUUID } from "node:crypto";
     2→import { execFile } from "node:child_process";
     3→import { promisify } from "node:util";
     4→import { copyFile, mkdir, readFile, writeFile } from "node:fs/promises";
     5→import { join } from "node:path";
     6→import { homedir } from "node:os";
     7→import { ProcessManager } from "./process-manager.js";
     8→import { AcceptanceWatcher } from "./acceptance-watcher.js";
     9→import type { StatusManager } from "./status-manager.js";
    10→import * as github from "./github.js";
    11→import * as worktree from "./worktree.js";
    12→import type { ShipProcess, ShipStatus, FleetSkillSources, PRReviewResponse, GateTransition, GateType, GateFileResponse, PersistedShip } from "./types.js";
    13→
    14→const SHIPS_FILE = join(homedir(), ".vibe-admiral", "ships.json");
    15→
    16→const execFileAsync = promisify(execFile);
    17→
    18→export class ShipManager {
    19→  private ships = new Map<string, ShipProcess>();
    20→  private processManager: ProcessManager;
    21→  private acceptanceWatcher: AcceptanceWatcher;
    22→  private statusManager: StatusManager;
    23→  private onStatusChange:
    24→    | ((id: string, status: ShipStatus, detail?: string) => void)
    25→    | null = null;
    26→
    27→  constructor(
    28→    processManager: ProcessManager,
    29→    acceptanceWatcher: AcceptanceWatcher,
    30→    statusManager: StatusManager,
    31→  ) {
    32→    this.processManager = processManager;
    33→    this.acceptanceWatcher = acceptanceWatcher;
    34→    this.statusManager = statusManager;
    35→  }
    36→
    37→  setStatusChangeHandler(
    38→    handler: (id: string, status: ShipStatus, detail?: string) => void,
    39→  ): void {
    40→    this.onStatusChange = handler;
    41→  }
    42→
    43→  async sortie(
    44→    fleetId: string,
    45→    repo: string,
    46→    issueNumber: number,
    47→    localPath: string,
    48→    skillSources?: FleetSkillSources,
    49→    extraPrompt?: string,
    50→    skill?: string,
    51→  ): Promise<ShipProcess> {
    52→    // Clean up all completed ships (done/error) on every new sortie
    53→    for (const [id, ship] of this.ships) {
    54→      if (ship.status === "done" || ship.status === "error") {
    55→        this.ships.delete(id);
    56→      }
    57→    }
    58→
    59→    const shipId = randomUUID();
    60→
    61→    // 1. Get issue info (used later for title, slug, etc.)
    62→    const issue = await github.getIssue(repo, issueNumber);
    63→
    64→    // 2. Update issue status: todo → doing (via StatusManager)
    65→    await this.statusManager.markDoing(repo, issueNumber);
    66→
    67→    // 3. Create worktree
    68→    const repoRoot = await worktree.getRepoRoot(localPath);
    69→    const defaultBranch = await github.getDefaultBranch(repo);
    70→    const slug = worktree.toKebabCase(issue.title);
    71→    const branchName = `feature/${issueNumber}-${slug}`;
    72→    const worktreePath = `${repoRoot}/.worktrees/feature/${issueNumber}-${slug}`;
    73→
    74→    await worktree.create(worktreePath, branchName, defaultBranch);
    75→
    76→    // 4. Symlink settings
    77→    await worktree.symlinkSettings(repoRoot, worktreePath);
    78→
    79→    // 5. Copy /implement skill to worktree
    80→    await this.deploySkills(repoRoot, worktreePath, skillSources);
    81→
    82→    // 6. npm install if web project
    83→    if (await worktree.isWebProject(worktreePath)) {
    84→      await execFileAsync("npm", ["install"], { cwd: worktreePath });
    85→    }
    86→
    87→    const ship: ShipProcess = {
    88→      id: shipId,
    89→      fleetId,
    90→      repo,
    91→      issueNumber,
    92→      issueTitle: issue.title,
    93→      status: "planning",
    94→      isCompacting: false,
    95→      branchName,
    96→      worktreePath,
    97→      sessionId: null,
    98→      prUrl: null,
    99→      prReviewStatus: null,
   100→      acceptanceTest: null,
   101→      acceptanceTestApproved: false,
   102→      gateCheck: null,
   103→      errorType: null,
   104→      retryCount: 0,
   105→      createdAt: new Date().toISOString(),
   106→      lastOutputAt: null,
   107→    };
   108→    this.ships.set(shipId, ship);
   109→
   110→    // 7. Launch Claude CLI process
   111→    this.processManager.sortie(shipId, worktreePath, issueNumber, extraPrompt, skill);
   112→
   113→    // 8. Start acceptance test watcher
   114→    this.acceptanceWatcher.watch(worktreePath, shipId);
   115→
   116→    this.updateStatus(shipId, "planning");
   117→    return ship;
   118→  }
   119→
   120→  stopShip(shipId: string): boolean {
   121→    const killed = this.processManager.kill(shipId);
   122→    if (killed) {
   123→      this.acceptanceWatcher.unwatch(shipId);
   124→      const ship = this.ships.get(shipId);
   125→      if (ship) ship.isCompacting = false;
   126→      this.updateStatus(shipId, "error", "Manually stopped");
   127→    }
   128→    return killed;
   129→  }
   130→
   131→  getShip(shipId: string): ShipProcess | undefined {
   132→    return this.ships.get(shipId);
   133→  }
   134→
   135→  /**
   136→   * Resolve a Ship by: exact UUID → prefix match → issueNumber fallback.
   137→   * Returns undefined if no match or if a prefix matches multiple ships.
   138→   */
   139→  resolveShip(shipId: string, issueNumber?: number): ShipProcess | undefined {
   140→    // 1. Exact match
   141→    const exact = this.ships.get(shipId);
   142→    if (exact) return exact;
   143→
   144→    // 2. Prefix match (only if shipId is shorter than a full UUID)
   145→    if (shipId.length < 36) {
   146→      const prefixMatches: ShipProcess[] = [];
   147→      for (const ship of this.ships.values()) {
   148→        if (ship.id.startsWith(shipId)) {
   149→          prefixMatches.push(ship);
   150→        }
   151→      }
   152→      if (prefixMatches.length === 1) return prefixMatches[0];
   153→    }
   154→
   155→    // 3. issueNumber fallback (active ships only)
   156→    if (issueNumber !== undefined) {
   157→      for (const ship of this.ships.values()) {
   158→        if (ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
   159→          return ship;
   160→        }
   161→      }
   162→    }
   163→
   164→    return undefined;
   165→  }
   166→
   167→  getShipsByFleet(fleetId: string): ShipProcess[] {
   168→    return Array.from(this.ships.values()).filter(
   169→      (s) => s.fleetId === fleetId,
   170→    );
   171→  }
   172→
   173→  getAllShips(): ShipProcess[] {
   174→    return Array.from(this.ships.values());
   175→  }
   176→
   177→  getShipByIssue(repo: string, issueNumber: number): ShipProcess | undefined {
   178→    for (const ship of this.ships.values()) {
   179→      if (ship.repo === repo && ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
   180→        return ship;
   181→      }
   182→    }
   183→    return undefined;
   184→  }
   185→
   186→  getActiveShipIssueNumbers(): Array<{ repo: string; issueNumber: number }> {
   187→    const active: Array<{ repo: string; issueNumber: number }> = [];
   188→    for (const ship of this.ships.values()) {
   189→      if (ship.status !== "done" && ship.status !== "error") {
   190→        active.push({ repo: ship.repo, issueNumber: ship.issueNumber });
   191→      }
   192→    }
   193→    return active;
   194→  }
   195→
   196→  hasRunningProcess(shipId: string): boolean {
   197→    return this.processManager.isRunning(shipId);
   198→  }
   199→
   200→  updateStatus(id: string, status: ShipStatus, detail?: string): void {
   201→    const ship = this.ships.get(id);
   202→    if (ship) {
   203→      // Defensive: clear acceptanceTest when leaving acceptance-test status
   204→      if (ship.status === "acceptance-test" && status !== "acceptance-test") {
   205→        ship.acceptanceTest = null;
   206→      }
   207→      ship.status = status;
   208→      if (status === "done" || status === "error") {
   209→        ship.completedAt = Date.now();
   210→      }
   211→      // Note: GitHub label sync is now handled transactionally by ShipRequestHandler.
   212→      // This method only updates in-memory state and notifies the frontend.
   213→      this.onStatusChange?.(id, status, detail);
   214→      this.persistToDisk();
   215→    }
   216→  }
   217→
   218→  setNothingToDo(id: string, reason: string): void {
   219→    const ship = this.ships.get(id);
   220→    if (ship) {
   221→      ship.nothingToDo = true;
   222→      ship.nothingToDoReason = reason;
   223→    }
   224→  }
   225→
   226→  async respondToPRReview(
   227→    shipId: string,
   228→    response: PRReviewResponse,
   229→  ): Promise<void> {
   230→    const ship = this.ships.get(shipId);
   231→    if (!ship) return;
   232→
   233→    ship.prReviewStatus = response.verdict === "approve" ? "approved" : "changes-requested";
   234→
   235→    // On request-changes, revert phase to implementing so Ship can fix
   236→    if (response.verdict === "request-changes") {
   237→      this.updateStatus(shipId, "implementing");
   238→    }
   239→
   240→    // Ensure .claude directory exists and write response file for Ship CLI
   241→    const claudeDir = join(ship.worktreePath, ".claude");
   242→    await mkdir(claudeDir, { recursive: true });
   243→    const responseFile = join(claudeDir, "pr-review-response.json");
   244→    await writeFile(responseFile, JSON.stringify(response, null, 2));
   245→  }
   246→
   247→  setAcceptanceTest(
   248→    shipId: string,
   249→    request: { url: string; checks: string[] },
   250→  ): void {
   251→    const ship = this.ships.get(shipId);
   252→    if (!ship) return;
   253→    ship.acceptanceTest = request;
   254→  }
   255→
   256→  clearAcceptanceTest(shipId: string): void {
   257→    const ship = this.ships.get(shipId);
   258→    if (!ship) return;
   259→    ship.acceptanceTest = null;
   260→  }
   261→
   262→  respondToAcceptanceTest(
   263→    shipId: string,
   264→    accepted: boolean,
   265→    feedback?: string,
   266→  ): void {
   267→    const ship = this.ships.get(shipId);
   268→    if (!ship) return;
   269→
   270→    if (accepted) {
   271→      ship.acceptanceTestApproved = true;
   272→    }
   273→
   274→    this.acceptanceWatcher
   275→      .respond(ship.worktreePath, { accepted, feedback })
   276→      .catch((err) => {
   277→        console.error(
   278→          `Failed to write acceptance test response for ${shipId}:`,
   279→          err,
   280→        );
   281→      });
   282→  }
   283→
   284→  setGateCheck(
   285→    shipId: string,
   286→    transition: GateTransition,
   287→    gateType: GateType,
   288→  ): void {
   289→    const ship = this.ships.get(shipId);
   290→    if (!ship) return;
   291→    ship.gateCheck = {
   292→      transition,
   293→      gateType,
   294→      status: "pending",
   295→      requestedAt: new Date().toISOString(),
   296→    };
   297→  }
   298→
   299→  clearGateCheck(shipId: string): void {
   300→    const ship = this.ships.get(shipId);
   301→    if (!ship) return;
   302→    ship.gateCheck = null;
   303→  }
   304→
   305→  async respondToGate(
   306→    shipId: string,
   307→    approved: boolean,
   308→    feedback?: string,
   309→  ): Promise<void> {
   310→    const ship = this.ships.get(shipId);
   311→    if (!ship || !ship.gateCheck) return;
   312→
   313→    ship.gateCheck.status = approved ? "approved" : "rejected";
   314→    if (feedback) ship.gateCheck.feedback = feedback;
   315→
   316→    // Write gate-response.json for Ship CLI to poll
   317→    const claudeDir = join(ship.worktreePath, ".claude");
   318→    await mkdir(claudeDir, { recursive: true });
   319→    const response: GateFileResponse = { approved, feedback };
   320→    await writeFile(
   321→      join(claudeDir, "gate-response.json"),
   322→      JSON.stringify(response, null, 2),
   323→    );
   324→  }
   325→
   326→  private async deploySkills(
   327→    repoRoot: string,
   328→    worktreePath: string,
   329→    skillSources?: FleetSkillSources,
   330→  ): Promise<void> {
   331→    // Copy /implement skill from the main repo's skills/ (or custom path)
   332→    // This is essential for Ship operation — failure is fatal.
   333→    const implementSrc = skillSources?.implement
   334→      ? join(skillSources.implement, "SKILL.md")
   335→      : join(repoRoot, "skills", "implement", "SKILL.md");
   336→    const implementDestDir = join(worktreePath, ".claude", "skills", "implement");
   337→    await mkdir(implementDestDir, { recursive: true });
   338→    await copyFile(implementSrc, join(implementDestDir, "SKILL.md"));
   339→
   340→    // Copy /adr skill from the main repo's skills/ (non-fatal)
   341→    const adrSrc = join(repoRoot, "skills", "adr", "SKILL.md");
   342→    const adrDestDir = join(worktreePath, ".claude", "skills", "adr");
   343→    try {
   344→      await mkdir(adrDestDir, { recursive: true });
   345→      await copyFile(adrSrc, join(adrDestDir, "SKILL.md"));
   346→    } catch {
   347→      console.warn("[ship-manager] Failed to deploy /adr skill");
   348→    }
   349→
   350→    // Copy dev-shared skills if devSharedDir is configured
   351→    const devSharedDir = skillSources?.devSharedDir;
   352→    if (!devSharedDir) return;
   353→
   354→    const devSharedSkills = ["review-pr", "second-opinion", "test", "refactor"];
   355→    for (const skillName of devSharedSkills) {
   356→      const src = join(devSharedDir, skillName, "SKILL.md");
   357→      const destDir = join(worktreePath, ".claude", "skills", skillName);
   358→      try {
   359→        await mkdir(destDir, { recursive: true });
   360→        await copyFile(src, join(destDir, "SKILL.md"));
   361→      } catch {
   362→        console.warn(`[ship-manager] Failed to deploy /${skillName} skill from dev-shared`);
   363→      }
   364→    }
   365→  }
   366→
   367→  /**
   368→   * Remove completed/error Ships that have no running process.
   369→   * Called during startup reconciliation to clear ghosts from previous runs.
   370→   */
   371→  purgeOrphanShips(): number {
   372→    let purged = 0;
   373→    for (const [id, ship] of this.ships) {
   374→      if (
   375→        (ship.status === "done" || ship.status === "error") &&
   376→        !this.processManager.isRunning(id)
   377→      ) {
   378→        this.ships.delete(id);
   379→        purged++;
   380→      }
   381→    }
   382→    if (purged > 0) {
   383→      console.log(`[ship-manager] Purged ${purged} orphan ship(s)`);
   384→      this.persistToDisk();
   385→    }
   386→    return purged;
   387→  }
   388→
   389→  /**
   390→   * Retry an errored Ship. If the Ship has a sessionId, resume the session.
   391→   * Otherwise, re-sortie from scratch.
   392→   * Returns the resumed/re-launched ShipProcess, or null if not retryable.
   393→   */
   394→  retryShip(
   395→    shipId: string,
   396→    extraPrompt?: string,
   397→    skill?: string,
   398→  ): ShipProcess | null {
   399→    const ship = this.ships.get(shipId);
   400→    if (!ship || ship.status !== "error") return null;
   401→
   402→    ship.retryCount++;
   403→    ship.errorType = null;
   404→
   405→    if (ship.sessionId) {
   406→      // Resume existing session
   407→      this.processManager.resumeSession(
   408→        shipId,
   409→        ship.sessionId,
   410→        "The previous session was interrupted. Continue from where you left off.",
   411→        ship.worktreePath,
   412→      );
   413→      this.updateStatus(shipId, "implementing", "Resumed from session");
   414→    } else {
   415→      // No session to resume — re-sortie
   416→      this.processManager.sortie(
   417→        shipId,
   418→        ship.worktreePath,
   419→        ship.issueNumber,
   420→        extraPrompt,
   421→        skill,
   422→      );
   423→      this.updateStatus(shipId, "planning", "Re-sortied");
   424→    }
   425→
   426→    this.acceptanceWatcher.watch(ship.worktreePath, shipId);
   427→    return ship;
   428→  }
   429→
   430→  stopAll(): void {
   431→    for (const [id] of this.ships) {
   432→      this.processManager.kill(id);
   433→    }
   434→    this.acceptanceWatcher.unwatchAll();
   435→  }
   436→
   437→  /**
   438→   * Persist active ships to disk so reconcileOnStartup can identify
   439→   * genuinely active ships after an Engine restart.
   440→   * Only ships with non-terminal statuses are persisted.
   441→   */
   442→  private persistToDisk(): void {
   443→    const active: PersistedShip[] = [];
   444→    for (const ship of this.ships.values()) {
   445→      if (ship.status !== "done" && ship.status !== "error") {
   446→        active.push({
   447→          id: ship.id,
   448→          fleetId: ship.fleetId,
   449→          repo: ship.repo,
   450→          issueNumber: ship.issueNumber,
   451→          issueTitle: ship.issueTitle,
   452→          worktreePath: ship.worktreePath,
   453→          branchName: ship.branchName,
   454→          sessionId: ship.sessionId,
   455→          status: ship.status,
   456→          createdAt: ship.createdAt,
   457→        });
   458→      }
   459→    }
   460→    // Fire-and-forget: persistence is best-effort, don't block the caller
   461→    const dir = join(homedir(), ".vibe-admiral");
   462→    mkdir(dir, { recursive: true })
   463→      .then(() => writeFile(SHIPS_FILE, JSON.stringify(active, null, 2)))
   464→      .catch((err) => {
   465→        console.warn("[ship-manager] Failed to persist ships to disk:", err);
   466→      });
   467→  }
   468→
   469→  /**
   470→   * Restore ships from disk persistence file.
   471→   * Called during startup reconciliation to recover active ship data
   472→   * that was lost when the Engine process restarted.
   473→   * Restored ships are added to the in-memory Map so that
   474→   * getActiveShipIssueNumbers() returns them during reconciliation.
   475→   */
   476→  async restoreFromDisk(): Promise<number> {
   477→    try {
   478→      const content = await readFile(SHIPS_FILE, "utf-8");
   479→      const persisted = JSON.parse(content) as PersistedShip[];
   480→      let restored = 0;
   481→      for (const ps of persisted) {
   482→        // Skip if a ship with this ID already exists in memory
   483→        if (this.ships.has(ps.id)) continue;
   484→        // Only restore ships that had active (non-terminal) statuses
   485→        if (ps.status === "done" || ps.status === "error") continue;
   486→
   487→        const ship: ShipProcess = {
   488→          id: ps.id,
   489→          fleetId: ps.fleetId,
   490→          repo: ps.repo,
   491→          issueNumber: ps.issueNumber,
   492→          issueTitle: ps.issueTitle,
   493→          worktreePath: ps.worktreePath,
   494→          branchName: ps.branchName,
   495→          sessionId: ps.sessionId,
   496→          status: ps.status,
   497→          isCompacting: false,
   498→          prUrl: null,
   499→          prReviewStatus: null,
   500→          acceptanceTest: null,
   501→          acceptanceTestApproved: false,
   502→          gateCheck: null,
   503→          errorType: null,
   504→          retryCount: 0,
   505→          createdAt: ps.createdAt,
   506→          lastOutputAt: null,
   507→        };
   508→        this.ships.set(ps.id, ship);
   509→        restored++;
   510→      }
   511→      if (restored > 0) {
   512→        console.log(`[ship-manager] Restored ${restored} ship(s) from disk`);
   513→      }
   514→      return restored;
   515→    } catch {
   516→      // File doesn't exist or is invalid — normal on first run
   517→      return 0;
   518→    }
   519→  }
   520→}
