     1→// === Ship Status ===
     2→export type ShipStatus =
     3→  | "planning"
     4→  | "implementing"
     5→  | "acceptance-test"
     6→  | "merging"
     7→  | "done"
     8→  | "error";
     9→
    10→/** Classification of Ship error cause. */
    11→export type ShipErrorType = "rate_limit" | "unknown";
    12→
    13→// === Gate ===
    14→
    15→/** A transition key in the format "from→to" (using full-width arrow). */
    16→export type GateTransition =
    17→  | "planning→implementing"
    18→  | "implementing→acceptance-test"
    19→  | "acceptance-test→merging";
    20→
    21→/** Gate type determines which Dispatch sub-agent or mechanism handles the check. */
    22→export type GateType = "plan-review" | "code-review" | "playwright";
    23→
    24→/** Per-gate configuration: true = default type, string = specific type, false = disabled. */
    25→export type GateConfig = boolean | GateType;
    26→
    27→/** Fleet-level gate settings. Omitted transitions use defaults. */
    28→export type FleetGateSettings = Partial<Record<GateTransition, GateConfig>>;
    29→
    30→/** Default gate types for each transition. */
    31→export const DEFAULT_GATE_TYPES: Record<GateTransition, GateType> = {
    32→  "planning→implementing": "plan-review",
    33→  "implementing→acceptance-test": "code-review",
    34→  "acceptance-test→merging": "playwright",
    35→};
    36→
    37→/** Status of a pending gate check. */
    38→export type GateStatus = "pending" | "approved" | "rejected";
    39→
    40→/** Gate check state stored on a Ship. */
    41→export interface GateCheckState {
    42→  transition: GateTransition;
    43→  gateType: GateType;
    44→  status: GateStatus;
    45→  feedback?: string;
    46→  requestedAt: string;
    47→  /** ISO timestamp when Bridge acknowledged receipt of the gate check. */
    48→  acknowledgedAt?: string;
    49→}
    50→
    51→// === Fleet ===
    52→export interface FleetRepo {
    53→  localPath: string;
    54→  remote?: string;
    55→}
    56→
    57→export interface FleetSkillSources {
    58→  implement?: string;
    59→  devSharedDir?: string;
    60→}
    61→
    62→export interface Fleet {
    63→  id: string;
    64→  name: string;
    65→  repos: FleetRepo[];
    66→  skillSources?: FleetSkillSources;
    67→  /** Rule files loaded for both Bridge and Ship sessions (fleet-wide context). */
    68→  sharedRulePaths?: string[];
    69→  /** Rule files loaded only for the Bridge session (e.g. triage policies). */
    70→  bridgeRulePaths?: string[];
    71→  /** Rule files loaded only for Ship sessions (e.g. implementation constraints). */
    72→  shipRulePaths?: string[];
    73→  /** Gate settings: which transition gates are enabled and their types. */
    74→  gates?: FleetGateSettings;
    75→  /** Maximum number of concurrent Ship sorties per fleet (default: 6). */
    76→  maxConcurrentSorties?: number;
    77→  createdAt: string;
    78→}
