    18→  constructor(shipManager: ShipManager, stateSync: StateSync) {
    19→    this.shipManager = shipManager;
    20→    this.stateSync = stateSync;
    21→  }
    22→
    23→  setShipRequestHandler(handler: ShipRequestHandler): void {
    24→    this.shipRequestHandler = handler;
    25→  }
    26→
    27→  setGateApprovedHandler(
    28→    handler: (shipId: string, transition: GateTransition) => void,
    29→  ): void {
    30→    this.onGateApproved = handler;
    31→  }
    32→
    33→  setGateRejectedHandler(
