    38→
    39→  async handle(
    40→    fleetId: string,
    41→    request: BridgeRequest,
    42→    fleetRepos: FleetRepo[],
    43→    repoRemotes: string[],
    44→    skillSources?: FleetSkillSources,
    45→    shipExtraPrompt?: string,
    46→    maxConcurrentSorties?: number,
    47→  ): Promise<string> {
    48→    switch (request.request) {
    49→      case "sortie":
    50→        return this.handleSortie(fleetId, request, fleetRepos, repoRemotes, skillSources, shipExtraPrompt, maxConcurrentSorties);
    51→      case "ship-status":
    52→        return this.handleShipStatus(fleetId);
    53→      case "ship-stop":
    54→        return this.handleShipStop(request);
    55→      case "pr-review-result":
    56→        return this.handlePRReviewResult(request);
    57→      case "gate-result":
    58→        return this.handleGateResult(request);
    59→      case "gate-ack":
    60→        return this.handleGateAck(request);
    61→    }
    62→  }
    63→
    64→  private async handleSortie(
    65→    fleetId: string,
    66→    request: Extract<BridgeRequest, { request: "sortie" }>,
    67→    fleetRepos: FleetRepo[],
    68→    repoRemotes: string[],
    69→    skillSources?: FleetSkillSources,
    70→    shipExtraPrompt?: string,
    71→    maxConcurrentSorties?: number,
    72→  ): Promise<string> {
    73→    // Determine concurrent sortie limit (static, not dynamically adjusted)
    74→    const configuredMax = maxConcurrentSorties ?? 6;
    75→    const activeShips = this.shipManager.getShipsByFleet(fleetId)
    76→      .filter((s: ShipProcess) => s.status !== "done" && s.status !== "error");
    77→    const availableSlots = Math.max(0, configuredMax - activeShips.length);
    78→
    79→    if (availableSlots === 0) {
    80→      return `[Sortie Throttled] Concurrent limit reached (${activeShips.length}/${configuredMax} active). Wait for Ships to complete.`;
    81→    }
    82→
    83→    const repoSet = new Set(repoRemotes);
    84→    const results: string[] = [];
    85→    let launched = 0;
    86→
    87→    for (const item of request.items) {
    88→      // Check per-item concurrent limit
    89→      if (launched >= availableSlots) {
    90→        results.push(
    91→          `Deferred ${item.repo}#${item.issueNumber}: concurrent limit reached (${configuredMax})`,
    92→        );
    93→        continue;
    94→      }
    95→      // Validate repo is in fleet whitelist
    96→      if (!repoSet.has(item.repo)) {
    97→        results.push(
    98→          `Rejected ${item.repo}#${item.issueNumber}: repo not registered in this fleet`,
    99→        );
   100→        continue;
   101→      }
   102→
   103→      // Run sortie guard
   104→      const guard = await this.stateSync.sortieGuard(item.repo, item.issueNumber);
   105→      if (!guard.ok) {
   106→        results.push(
   107→          `Blocked ${item.repo}#${item.issueNumber}: ${guard.reason}`,
   108→        );
   109→        continue;
   110→      }
   111→
   112→      // Find local path
   113→      const repoEntry = fleetRepos.find(
   114→        (r) => r.remote === item.repo || r.localPath === item.repo,
   115→      );
   116→      if (!repoEntry) {
   117→        results.push(
   118→          `Failed ${item.repo}#${item.issueNumber}: no local path registered`,
   119→        );
   120→        continue;
   121→      }
   122→
   123→      try {
   124→        const ship = await this.shipManager.sortie(
   125→          fleetId,
   126→          item.repo,
   127→          item.issueNumber,
   128→          repoEntry.localPath,
   129→          skillSources,
   130→          shipExtraPrompt,
   131→          item.skill,
   132→        );
   133→        launched++;
   134→        results.push(
   135→          `Ship ${ship.id} launched for ${item.repo}#${item.issueNumber} (${ship.issueTitle})`,
   136→        );
   137→      } catch (err) {
   138→        results.push(
   139→          `Failed ${item.repo}#${item.issueNumber}: ${err instanceof Error ? err.message : String(err)}`,
   140→        );
   141→      }
   142→    }
   143→
   144→    return `[Sortie Results]\n${results.join("\n")}`;
   145→  }
   146→
   147→  private handleShipStatus(fleetId: string): string {
   148→    const ships = this.shipManager.getShipsByFleet(fleetId);
   149→    if (ships.length === 0) {
   150→      return "[Ship Status] No active ships in this fleet.";
   151→    }
   152→    const lines = ships.map(
   153→      (s) =>
   154→        `  Ship ${s.id} #${s.issueNumber} (${s.issueTitle}): ${s.status}${s.gateCheck ? ` [gate: ${s.gateCheck.transition} ${s.gateCheck.status}]` : ""}\n    Worktree: ${s.worktreePath}\n    Log: ${s.worktreePath}/.claude/ship-log.jsonl`,
   155→    );
   156→    return `[Ship Status]\n${lines.join("\n")}`;
   157→  }
   158→
   159→  private handleShipStop(
   160→    request: Extract<BridgeRequest, { request: "ship-stop" }>,
   161→  ): string {
   162→    const ship = this.shipManager.resolveShip(request.shipId);
   163→    if (!ship) {
   164→      return `[Stop Ship Failed] Ship ${request.shipId} not found or already stopped`;
   165→    }
   166→    const killed = this.shipManager.stopShip(ship.id);
   167→    if (killed) {
   168→      return `[Ship Stopped] ${ship.id}`;
   169→    }
   170→    return `[Stop Ship Failed] Ship ${request.shipId} not found or already stopped`;
   171→  }
   172→
   173→  private handlePRReviewResult(
   174→    request: Extract<BridgeRequest, { request: "pr-review-result" }>,
   175→  ): string {
   176→    const ship = this.shipManager.resolveShip(request.shipId);
   177→    if (!ship) {
   178→      return `[PR Review Failed] Ship ${request.shipId} not found`;
   179→    }
   180→
   181→    this.shipManager.respondToPRReview(ship.id, {
   182→      verdict: request.verdict,
   183→      comments: request.comments,
   184→    });
   185→
   186→    const label = request.verdict === "approve" ? "APPROVED" : "CHANGES REQUESTED";
   187→    return `[PR Review Result] Ship #${ship.issueNumber} PR #${request.prNumber}: ${label}${request.comments ? ` — ${request.comments}` : ""}`;
   188→  }
   189→
   190→  private handleGateAck(
   191→    request: Extract<BridgeRequest, { request: "gate-ack" }>,
   192→  ): string {
   193→    const ship = this.shipManager.resolveShip(request.shipId, request.issueNumber);
   194→    if (!ship) {
   195→      return `[Gate ACK Failed] Ship ${request.shipId} not found`;
   196→    }
   197→
   198→    if (!ship.gateCheck || ship.gateCheck.transition !== request.transition) {
   199→      return `[Gate ACK Failed] Ship #${ship.issueNumber} has no pending gate for ${request.transition}`;
   200→    }
   201→
   202→    if (ship.gateCheck.status !== "pending") {
   203→      return `[Gate ACK Failed] Ship #${ship.issueNumber} gate for ${request.transition} is already ${ship.gateCheck.status}`;
   204→    }
   205→
   206→    ship.gateCheck.acknowledgedAt = new Date().toISOString();
   207→    console.log(
   208→      `[bridge-request] Gate ACK received for Ship #${ship.issueNumber}: ${request.transition} — timeout window reset`,
   209→    );
   210→    return `[Gate ACK] Ship #${ship.issueNumber}: ${request.transition} acknowledged — timeout window reset`;
   211→  }
   212→
   213→  private async handleGateResult(
   214→    request: Extract<BridgeRequest, { request: "gate-result" }>,
   215→  ): Promise<string> {
   216→    const ship = this.shipManager.resolveShip(request.shipId, request.issueNumber);
   217→    if (!ship) {
   218→      return `[Gate Result Failed] Ship ${request.shipId} not found`;
   219→    }
   220→
   221→    if (!ship.gateCheck || ship.gateCheck.transition !== request.transition) {
   222→      return `[Gate Result Failed] Ship #${ship.issueNumber} has no pending gate for ${request.transition}`;
   223→    }
   224→
   225→    if (ship.gateCheck.status !== "pending") {
   226→      return `[Gate Result Failed] Ship #${ship.issueNumber} gate for ${request.transition} is already ${ship.gateCheck.status}`;
   227→    }
   228→
   229→    const approved = request.verdict === "approve";
   230→    await this.shipManager.respondToGate(
   231→      ship.id,
   232→      approved,
   233→      request.feedback,
   234→    );
   235→
   236→    if (approved) {
   237→      // Execute the gated transition
   238→      const { to } = parseTransition(request.transition);
   239→      if (this.shipRequestHandler) {
   240→        const result = await this.shipRequestHandler.executeGatedTransition(
   241→          ship.id,
   242→          to,
   243→        );
   244→        if (result.ok) {
   245→          this.onGateApproved?.(ship.id, request.transition);
   246→          return `[Gate Approved] Ship #${ship.issueNumber}: ${request.transition} — transition confirmed`;
   247→        }
   248→        return `[Gate Approved but Transition Failed] Ship #${ship.issueNumber}: ${result.error}`;
   249→      }
   250→      return `[Gate Approved] Ship #${ship.issueNumber}: ${request.transition}`;
   251→    }
   252→
   253→    this.onGateRejected?.(ship.id, request.transition, request.feedback);
   254→    return `[Gate Rejected] Ship #${ship.issueNumber}: ${request.transition}${request.feedback ? ` — ${request.feedback}` : ""}`;
   255→  }
   256→}
