   112→            data: { source: "ws", message: `Invalid message: ${err}` },
   113→          });
   114→        }
   115→      });
   116→
   117→      ws.on("close", () => {
   118→        this.clients.delete(ws);
   119→        console.log("Client disconnected");
   120→      });
   121→    });
   122→  }
