   124→  private setupProcessEvents(): void {
   125→    this.processManager.on("data", (id: string, msg: Record<string, unknown>) => {
   126→      // Route to bridge or ship
   127→      if (id.startsWith("bridge-")) {
   128→        const fleetId = id.replace("bridge-", "");
   129→
   130→        // Extract sessionId from Bridge init messages (before parsing drops them)
   131→        const sessionId = extractSessionId(msg);
   132→        if (sessionId) {
   133→          this.bridgeManager.setSessionId(fleetId, sessionId);
   134→          console.log(
   135→            `[ws-server] Bridge ${id} sessionId captured: ${sessionId.slice(0, 12)}...`,
   136→          );
   137→        }
   138→
   139→        // Emit "connected" status on first data from bridge CLI
   140→        if (!this.bridgeFirstData.has(id)) {
   141→          this.bridgeFirstData.add(id);
   142→          const pid = this.processManager.getPid(id);
   143→          const connMsg = {
   144→            type: "system" as const,
   145→            subtype: "bridge-status" as const,
   146→            content: `Bridge CLI connected${pid ? ` (pid: ${pid})` : ""}`,
   147→          };
   148→          this.bridgeManager.addToHistory(fleetId, connMsg);
   149→          this.broadcast({
   150→            type: "bridge:stream",
   151→            data: { fleetId, message: connMsg },
   152→          });
   153→        }
   154→
   155→        const parsed = parseStreamMessage(msg);
   156→        if (parsed) {
   157→          // AskUserQuestion tool_use — forward as bridge:question
   158→          if (
   159→            parsed.type === "tool_use" &&
   160→            parsed.tool === "AskUserQuestion"
   161→          ) {
   162→            const toolInput = parsed.toolInput as Record<string, unknown> | undefined;
   163→            const question = toolInput?.question as string | undefined;
   164→            const toolUseId = parsed.toolUseId as string | undefined;
   165→            const questionMessage: StreamMessage = {
   166→              type: "question",
   167→              content: question ?? "Bridge is asking a question",
   168→              ...(toolUseId ? { toolUseId } : {}),
   169→            };
   170→            this.bridgeManager.addToHistory(fleetId, questionMessage);
   171→            // Track pending question for timeout and bridge:send guard
   172→            if (toolUseId) {
   173→              this.bridgeManager.setPendingQuestion(fleetId, toolUseId);
   174→            }
   175→            this.broadcast({
   176→              type: "bridge:question",
   177→              data: { fleetId, message: questionMessage },
   178→            });
   179→          // Check for admiral-request blocks in assistant text
   180→          } else if (parsed.type === "assistant" && parsed.content) {
   181→            const allRequests = extractRequests(parsed.content);
   182→            // Filter to Bridge-only requests (Ship requests from Bridge are ignored)
   183→            const requests = allRequests.filter(isBridgeRequest);
   184→            const cleanContent = stripRequestBlocks(parsed.content);
   185→
   186→            // Broadcast clean text (without request blocks) to frontend
   187→            if (cleanContent) {
   188→              const cleanMessage = { ...parsed, content: cleanContent };
   189→              this.bridgeManager.addToHistory(fleetId, cleanMessage);
   190→              this.broadcast({
   191→                type: "bridge:stream",
   192→                data: { fleetId, message: cleanMessage },
   193→              });
   194→            }
   195→
   196→            // Execute requests sequentially and batch results
   197→            if (requests.length > 0) {
   198→              const bridgeId = `bridge-${fleetId}`;
   199→              this.executeRequestsSequentially(fleetId, bridgeId, requests);
   200→            }
   201→          } else if (parsed.type !== "result") {
   202→            // Non-assistant or no content — pass through normally
   203→            // Skip "result" messages: they duplicate the preceding "assistant" text
   204→            this.bridgeManager.addToHistory(fleetId, parsed);
   205→            this.broadcast({
   206→              type: "bridge:stream",
   207→              data: { fleetId, message: parsed },
   208→            });
   209→          }
   210→        }
   211→      } else {
   212→        // Update lastOutputAt for Lookout no-output detection
   213→        {
   214→          const ship = this.shipManager.getShip(id);
   215→          if (ship) ship.lastOutputAt = Date.now();
   216→        }
   217→
   218→        // Extract sessionId from init messages (before parsing drops them)
   219→        const sessionId = extractSessionId(msg);
   220→        if (sessionId) {
   221→          const ship = this.shipManager.getShip(id);
   222→          if (ship && !ship.sessionId) {
   223→            ship.sessionId = sessionId;
   224→            console.log(
   225→              `[ws-server] Ship ${id.slice(0, 8)}... sessionId captured: ${sessionId.slice(0, 12)}...`,
   226→            );
   227→          }
   228→        }
   229→
   230→        // Detect compact status changes from raw message (before parsing)
   231→        this.detectCompactStatus(id, msg);
   232→
   233→        // Ship stream — parse raw CLI JSON before broadcast
   234→        const parsed = parseStreamMessage(msg);
   235→        if (parsed) {
   236→          // Check for admiral-request blocks in Ship assistant text
   237→          if (parsed.type === "assistant" && parsed.content) {
   238→            const requests = extractRequests(parsed.content);
   239→            const cleanContent = stripRequestBlocks(parsed.content);
   240→
   241→            // Broadcast clean text (without request blocks) to frontend
   242→            if (cleanContent) {
   243→              const cleanMessage = { ...parsed, content: cleanContent };
   244→              this.logShipMessage(id, cleanMessage);
   245→              this.broadcast({
   246→                type: "ship:stream",
   247→                data: { id, message: cleanMessage },
   248→              });
   249→            }
   250→
   251→            // Detect PR URL BEFORE processing admiral-requests so that
   252→            // ship.prUrl is populated when gate check messages are built.
   253→            // Fixes #293: code-review gate showing "PR: not yet created"
   254→            // when PR URL and status-transition appear in the same message.
   255→            if (cleanContent) {
   256→              const cleanMsg = { ...parsed, content: cleanContent };
   257→              this.detectPRCreation(id, cleanMsg);
   258→              this.detectPushForReReview(id, cleanMsg);
   259→            }
   260→
   261→            // Execute Ship requests (only status-transition allowed)
   262→            // Serialized per-ship to prevent race conditions with duplicate
   263→            // admiral-request blocks from cumulative stream-json messages.
   264→            const shipRequests = requests.filter(isShipRequest);
   265→            if (shipRequests.length > 0) {
   266→              const prev = this.shipRequestLocks.get(id) ?? Promise.resolve();
   267→              const next = prev.then(() => this.executeShipRequests(id, shipRequests)).catch(console.error);
   268→              this.shipRequestLocks.set(id, next);
   269→            }
   270→
   271→            // Reject any Bridge-only requests from Ship
   272→            const bridgeOnly = requests.filter(isBridgeRequest);
   273→            if (bridgeOnly.length > 0) {
   274→              console.warn(
   275→                `[ws-server] Ship ${id} attempted Bridge-only requests: ${bridgeOnly.map((r) => r.request).join(", ")}`,
   276→              );
   277→            }
   278→          } else {
   279→            this.logShipMessage(id, parsed);
   280→            this.broadcast({
   281→              type: "ship:stream",
   282→              data: { id, message: parsed },
   283→            });
   284→
   285→            // Detect PR URL in result messages and notify Bridge
   286→            this.detectPRCreation(id, parsed);
   287→            // Detect git push after request-changes for re-review
   288→            this.detectPushForReReview(id, parsed);
   289→          }
   290→        }
   291→      }
   292→    });
   293→
   294→    this.processManager.on("exit", (id: string, code: number | null) => {
   295→      if (id.startsWith("bridge-")) {
   296→        this.bridgeFirstData.delete(id);
   297→        const fleetId = id.replace("bridge-", "");
   298→        console.log(`Bridge ${id} exited with code ${code}`);
   299→        this.broadcast({
   300→          type: "bridge:stream",
   301→          data: {
   302→            fleetId,
   303→            message: {
   304→              type: code === 0 ? "system" : "error",
   305→              content:
   306→                code === 0
   307→                  ? "Bridge session ended."
   308→                  : `Bridge process exited with code ${code}.`,
   309→            },
   310→          },
   311→        });
   312→      } else {
   313→        console.log(`Ship ${id} exited with code ${code}`);
   314→        this.shipRequestLocks.delete(id);
   315→        const ship = this.shipManager.getShip(id);
   316→        if (!ship) {
   317→          console.warn(`[ws-server] Ship ${id} exited but is not tracked — skipping cleanup`);
   318→          return;
   319→        }
   320→        // Ship explicitly declares "done" via admiral-request status-transition.
   321→        // If the process exits while in "done" status, treat as success.
   322→        // If in "merging" status (squash merge may kill the process), also treat as success.
   323→        const successPhases = new Set(["done", "merging"]);
   324→        if (successPhases.has(ship.status)) {
   325→          this.stateSync.onProcessExit(id, true).catch(console.error);
   326→        } else {
   327→          // Process exited without declaring done — treat as failure.
   328→          // If rate-limited, the ship will be in "error" state and the user
   329→          // can manually retry via the UI Retry button.
   330→          this.stateSync.onProcessExit(id, false).catch(console.error);
   331→        }
   332→      }
   333→    });
   334→
   335→    this.processManager.on("rate-limit", (id: string) => {
   336→      if (id.startsWith("bridge-")) {
   337→        console.warn(`[ws-server] Bridge ${id} hit rate limit`);
   338→        return;
   339→      }
   340→      const ship = this.shipManager.getShip(id);
   341→      if (!ship) return;
   342→      ship.errorType = "rate_limit";
   343→      console.warn(
   344→        `[ws-server] Ship ${id.slice(0, 8)}... hit rate limit — will stop and await manual retry`,
   345→      );
   346→    });
   347→
   348→    this.processManager.on("error", (id: string, error: Error) => {
   349→      console.error(`Process ${id} error:`, error.message);
   350→      if (id.startsWith("bridge-")) {
   351→        const fleetId = id.replace("bridge-", "");
   352→        const hadData = this.bridgeFirstData.has(id);
   353→        this.bridgeFirstData.delete(id);
   354→        // Only show "Failed to start" if bridge never sent data (spawn failure)
   355→        if (!hadData) {
   356→          const errMsg = {
   357→            type: "system" as const,
   358→            subtype: "bridge-status" as const,
   359→            content: `Failed to start Bridge CLI: ${error.message}`,
   360→          };
   361→          this.bridgeManager.addToHistory(fleetId, errMsg);
   362→          this.broadcast({
   363→            type: "bridge:stream",
   364→            data: { fleetId, message: errMsg },
   365→          });
   366→        }
   367→      }
   368→      this.broadcast({
   369→        type: "error",
   370→        data: { source: id, message: error.message },
   371→      });
   372→    });
   373→  }
