   505→  private async handleMessage(
   506→    ws: WebSocket,
   507→    msg: ClientMessage,
   508→  ): Promise<void> {
   509→    const data = msg.data ?? {};
   510→
   511→    try {
   512→      switch (msg.type) {
   513→        // Fleet operations
   514→        case "fleet:create": {
   515→          const newFleet = await this.createFleet(
   516→            data.name as string,
   517→            data.repos as FleetRepo[],
   518→          );
   519→          const fleets = await this.loadFleets();
   520→          this.sendTo(ws, {
   521→            type: "fleet:created",
   522→            data: { id: newFleet.id, fleets },
   523→          });
   524→          break;
   525→        }
   526→        case "fleet:list": {
   527→          const fleets = await this.loadFleets();
   528→          this.sendTo(ws, { type: "fleet:data", data: fleets });
   529→          break;
   530→        }
   531→        case "fleet:select": {
   532→          const fleets = await this.loadFleets();
   533→          this.sendTo(ws, { type: "fleet:data", data: fleets });
   534→          break;
   535→        }
   536→        case "fleet:update": {
   537→          await this.updateFleet(data.id as string, data);
   538→          const fleets = await this.loadFleets();
   539→          this.sendTo(ws, { type: "fleet:data", data: fleets });
   540→          break;
   541→        }
   542→        case "fleet:delete": {
   543→          await this.deleteFleet(data.id as string);
   544→          const fleets = await this.loadFleets();
   545→          this.sendTo(ws, { type: "fleet:data", data: fleets });
   546→          break;
   547→        }
   548→
   549→        // Bridge operations
   550→        case "bridge:send": {
   551→          const fleetId = data.fleetId as string;
   552→          const message = data.message as string;
   553→
   554→          // Guard: reject if a question is pending
   555→          const pending = this.bridgeManager.getPendingQuestion(fleetId);
   556→          if (pending) {
   557→            this.sendTo(ws, {
   558→              type: "error",
   559→              data: {
   560→                source: "bridge:send",
   561→                message: "Cannot send a command while a question is pending. Please answer the question first.",
   562→              },
   563→            });
   564→            break;
   565→          }
   566→
   567→          const rawImages = data.images as Array<{ base64: string; mediaType: string }> | undefined;
   568→          const ALLOWED_MEDIA = new Set(["image/png", "image/jpeg", "image/gif", "image/webp"]);
   569→          const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5 MB base64 (~3.75 MB raw)
   570→          const MAX_IMAGES = 10;
   571→          const images = rawImages
   572→            ?.filter((img) => ALLOWED_MEDIA.has(img.mediaType) && img.base64.length <= MAX_IMAGE_SIZE)
   573→            .slice(0, MAX_IMAGES);
   574→          if (
   575→            !this.bridgeManager.hasSession(fleetId) &&
   576→            !this.launchingBridges.has(fleetId)
   577→          ) {
   578→            this.launchingBridges.add(fleetId);
   579→            try {
   580→              const fleets = await this.loadFleets();
   581→              const fleet = fleets.find((f) => f.id === fleetId);
   582→              if (!fleet) {
   583→                throw new Error(`Fleet not found: ${fleetId}`);
   584→              }
   585→              const remoteNames = fleet.repos
   586→                .map((r) => r.remote)
   587→                .filter((r): r is string => r !== undefined);
   588→              let prompt = buildBridgeSystemPrompt(
   589→                fleet.name,
   590→                remoteNames,
   591→                fleet.maxConcurrentSorties ?? 6,
   592→              );
   593→
   594→              // Load and append shared + bridge rules
   595→              const sharedRules = await this.loadRules(fleet.sharedRulePaths ?? []);
   596→              const bridgeRules = await this.loadRules(fleet.bridgeRulePaths ?? []);
   597→              const rulesSuffix = [sharedRules, bridgeRules].filter(Boolean).join("\n\n");
   598→              if (rulesSuffix) {
   599→                prompt = `${prompt}\n\n## Additional Rules\n\n${rulesSuffix}`;
   600→              }
   601→
   602→              await this.bridgeManager.launch(
   603→                fleetId,
   604→                process.cwd(),
   605→                [],
   606→                prompt,
   607→              );
   608→
   609→              // Notify frontend that bridge is starting (after successful launch)
   610→              const startMsg = {
   611→                type: "system" as const,
   612→                subtype: "bridge-status" as const,
   613→                content: "Starting Bridge session...",
   614→              };
   615→              this.bridgeManager.addToHistory(fleetId, startMsg);
   616→              this.broadcast({
   617→                type: "bridge:stream",
   618→                data: { fleetId, message: startMsg },
   619→              });
   620→            } finally {
   621→              this.launchingBridges.delete(fleetId);
   622→            }
   623→          }
   624→          this.bridgeManager.send(fleetId, message, images);
   625→          break;
   626→        }
   627→        case "bridge:answer": {
   628→          const ansFleetId = data.fleetId as string;
   629→          const answer = data.answer as string;
   630→          const toolUseId = data.toolUseId as string | undefined;
   631→          const bridgeId = `bridge-${ansFleetId}`;
   632→
   633→          // Clear pending question state
   634→          this.bridgeManager.clearPendingQuestion(ansFleetId);
   635→
   636→          // Record answer in history (no broadcast — frontend uses optimistic update)
   637→          const answerMessage: StreamMessage = {
   638→            type: "user",
   639→            content: answer,
   640→          };
   641→          this.bridgeManager.addToHistory(ansFleetId, answerMessage);
   642→
   643→          // Send answer to Bridge stdin as tool_result if toolUseId is available
   644→          if (toolUseId) {
   645→            this.processManager.sendToolResult(bridgeId, toolUseId, answer);
   646→          } else {
   647→            this.processManager.sendMessage(bridgeId, answer);
   648→          }
   649→          break;
   650→        }
   651→        case "bridge:history": {
   652→          const history = this.bridgeManager.getHistory(
   653→            data.fleetId as string,
   654→          );
   655→          this.sendTo(ws, {
   656→            type: "bridge:stream",
   657→            data: {
   658→              fleetId: data.fleetId as string,
   659→              message: { type: "history", content: JSON.stringify(history) },
   660→            },
   661→          });
   662→          break;
   663→        }
   664→
   665→        // Ship operations
   666→        case "ship:sortie": {
   667→          const fleets = await this.loadFleets();
   668→          const fleet = fleets.find((f) => f.id === (data.fleetId as string));
   669→          const repoStr = data.repo as string;
   670→          const repoEntry = fleet?.repos.find(
   671→            (r) => r.remote === repoStr || r.localPath === repoStr,
   672→          );
   673→          if (!repoEntry) {
   674→            throw new Error(
   675→              `Repo "${data.repo}" not found in fleet. Register the local path first.`,
   676→            );
   677→          }
   678→
   679→          // Sortie guard check
   680→          const remoteId = repoEntry.remote ?? repoStr;
   681→          const guard = await this.stateSync.sortieGuard(remoteId, data.issueNumber as number);
   682→          if (!guard.ok) {
   683→            throw new Error(guard.reason ?? "Sortie guard check failed");
   684→          }
   685→
   686→          // Load shared + ship rules for extraPrompt
   687→          const sharedRulesForShip = await this.loadRules(fleet?.sharedRulePaths ?? []);
   688→          const shipRules = await this.loadRules(fleet?.shipRulePaths ?? []);
   689→          const shipExtraPrompt = [sharedRulesForShip, shipRules].filter(Boolean).join("\n\n") || undefined;
   690→
   691→          const ship = await this.shipManager.sortie(
   692→            data.fleetId as string,
   693→            data.repo as string,
   694→            data.issueNumber as number,
   695→            repoEntry.localPath,
   696→            fleet?.skillSources,
   697→            shipExtraPrompt,
   698→          );
   699→          this.broadcast({
   700→            type: "ship:created",
   701→            data: {
   702→              id: ship.id,
   703→              fleetId: ship.fleetId,
   704→              repo: ship.repo,
   705→              issueNumber: ship.issueNumber,
   706→              issueTitle: ship.issueTitle,
   707→              status: ship.status,
   708→              branchName: ship.branchName,
   709→            },
   710→          });
   711→          break;
   712→        }
   713→        case "ship:chat": {
   714→          const ship = this.shipManager.getShip(data.id as string);
   715→          if (ship?.sessionId) {
   716→            this.processManager.resumeSession(
   717→              data.id as string,
   718→              ship.sessionId,
   719→              data.message as string,
   720→              ship.worktreePath,
   721→            );
   722→          }
   723→          break;
   724→        }
   725→        case "ship:accept": {
   726→          const acceptId = data.id as string;
   727→          this.shipManager.respondToAcceptanceTest(acceptId, true);
   728→          // Transactional: sync GitHub label before updating internal state
   729→          const acceptShip = this.shipManager.getShip(acceptId);
   730→          if (acceptShip) {
   731→            this.shipManager.clearAcceptanceTest(acceptId);
   732→            try {
   733→              await this.statusManager.syncPhaseLabel(acceptShip.repo, acceptShip.issueNumber, "merging");
   734→              this.shipManager.updateStatus(acceptId, "merging");
   735→            } catch (err) {
   736→              console.warn(`[ws-server] Failed to sync label for ship:accept #${acceptShip.issueNumber}:`, err);
   737→              // Still update internal state — the Ship already received the accept response
   738→              this.shipManager.updateStatus(acceptId, "merging");
   739→            }
   740→          }
   741→          break;
   742→        }
   743→        case "ship:reject": {
   744→          const rejectId = data.id as string;
   745→          this.shipManager.respondToAcceptanceTest(
   746→            rejectId,
   747→            false,
   748→            data.feedback as string,
   749→          );
   750→          // Transactional: sync GitHub label before updating internal state
   751→          const rejectShip = this.shipManager.getShip(rejectId);
   752→          if (rejectShip) {
   753→            this.shipManager.clearAcceptanceTest(rejectId);
   754→            try {
   755→              await this.statusManager.syncPhaseLabel(rejectShip.repo, rejectShip.issueNumber, "implementing");
   756→              this.shipManager.updateStatus(rejectId, "implementing");
   757→            } catch (err) {
   758→              console.warn(`[ws-server] Failed to sync label for ship:reject #${rejectShip.issueNumber}:`, err);
   759→              // Still update internal state — the Ship already received the reject response
   760→              this.shipManager.updateStatus(rejectId, "implementing");
   761→            }
   762→          }
   763→          break;
   764→        }
   765→        case "ship:retry": {
   766→          const retryId = data.id as string;
   767→          const retryShip = this.shipManager.getShip(retryId);
   768→          if (!retryShip || retryShip.status !== "error") {
   769→            throw new Error(`Ship "${retryId}" is not in error state`);
   770→          }
   771→
   772→          // Load ship rules for re-sortie fallback
   773→          const retriedFleets = await this.loadFleets();
   774→          const retryFleet = retriedFleets.find((f) => f.id === retryShip.fleetId);
   775→          const retrySharedRules = await this.loadRules(retryFleet?.sharedRulePaths ?? []);
   776→          const retryShipRules = await this.loadRules(retryFleet?.shipRulePaths ?? []);
   777→          const retryExtraPrompt = [retrySharedRules, retryShipRules].filter(Boolean).join("\n\n") || undefined;
   778→
   779→          const result = this.shipManager.retryShip(retryId, retryExtraPrompt);
   780→          if (!result) {
   781→            throw new Error(`Failed to retry Ship "${retryId}"`);
   782→          }
   783→          break;
   784→        }
   785→        case "ship:stop": {
   786→          const stopId = data.id as string;
   787→          const stopShip = this.shipManager.getShip(stopId);
   788→          this.shipManager.stopShip(stopId);
   789→          // Explicitly rollback label — don't rely solely on process exit handler
   790→          if (stopShip) {
   791→            this.stateSync.rollbackLabel(stopShip.repo, stopShip.issueNumber).catch((err) => {
   792→              console.warn(`[ws-server] Failed to rollback label on ship:stop for #${stopShip.issueNumber}:`, err);
   793→            });
   794→          }
   795→          break;
   796→        }
   797→        case "ship:logs": {
   798→          // Ship logs are streamed in real-time, no separate endpoint needed
   799→          break;
   800→        }
   801→        case "ship:list": {
   802→          const ships = this.shipManager.getAllShips();
   803→          this.sendTo(ws, { type: "ship:data", data: ships });
   804→          break;
   805→        }
   806→
   807→        // Issue operations (deterministic - no LLM)
   808→        case "issue:list": {
   809→          const issues = await github.listIssues(data.repo as string);
   810→          this.sendTo(ws, {
   811→            type: "issue:data",
   812→            data: { repo: data.repo as string, issues },
   813→          });
   814→          break;
   815→        }
   816→        case "issue:get": {
   817→          const issue = await github.getIssue(
   818→            data.repo as string,
   819→            data.number as number,
   820→          );
   821→          this.sendTo(ws, {
   822→            type: "issue:data",
   823→            data: { repo: data.repo as string, issues: [issue] },
   824→          });
   825→          break;
   826→        }
   827→
   828→        // Filesystem operations (localhost-only; returns dir names, no file content)
   829→        case "fs:list-dir": {
   830→          const dirPath = (data.path as string) || homedir();
   831→          const resolved = await realpath(resolve(dirPath));
   832→          const s = await stat(resolved);
   833→          if (!s.isDirectory()) {
   834→            throw new Error(`Not a directory: "${resolved}"`);
   835→          }
   836→          const dirents = await readdir(resolved, { withFileTypes: true });
   837→          const entries = dirents
   838→            .filter((d) => !d.name.startsWith("."))
   839→            .map((d) => ({ name: d.name, isDirectory: d.isDirectory() }))
   840→            .sort((a, b) => {
   841→              if (a.isDirectory !== b.isDirectory) return a.isDirectory ? -1 : 1;
   842→              return a.name.localeCompare(b.name);
   843→            });
   844→          this.sendTo(ws, {
   845→            type: "fs:dir-listing",
   846→            data: { path: resolved, entries },
   847→          });
   848→          break;
   849→        }
   850→
   851→        default:
   852→          this.sendTo(ws, {
   853→            type: "error",
   854→            data: { source: "ws", message: `Unknown message type: ${msg.type}` },
   855→          });
   856→      }
   857→    } catch (err) {
   858→      this.sendTo(ws, {
   859→        type: "error",
   860→        data: {
   861→          source: msg.type,
   862→          message: err instanceof Error ? err.message : String(err),
   863→        },
   864→      });
   865→    }
   866→  }
