   868→  // Fleet persistence
   869→  private async loadFleets(): Promise<Fleet[]> {
   870→    try {
   871→      const content = await readFile(FLEETS_FILE, "utf-8");
   872→      const parsed = JSON.parse(content) as Fleet[];
   873→      let migrated = false;
   874→      for (const fleet of parsed) {
   875→        if (fleet.repos?.length > 0 && typeof fleet.repos[0] === "string") {
   876→          fleet.repos = (fleet.repos as unknown as string[]).map((remote) => ({
   877→            localPath: "",
   878→            remote,
   879→          }));
   880→          migrated = true;
   881→        }
   882→      }
   883→      if (migrated) {
   884→        await this.saveFleets(parsed);
   885→      }
   886→      return parsed;
   887→    } catch {
   888→      return [];
   889→    }
   890→  }
