   897→  private async resolveRemote(localPath: string): Promise<string | undefined> {
   898→    try {
   899→      const { stdout } = await execFileAsync("git", [
   900→        "remote",
   901→        "get-url",
   902→        "origin",
   903→      ], { cwd: localPath });
   904→      const url = stdout.trim();
   905→      if (!url) return undefined;
   906→      // Extract owner/repo from GitHub URL (handle trailing slashes)
   907→      const match = url.match(/github\.com[:/](.+?)(?:\.git)?\/*$/);
   908→      if (match) return match[1];
   909→      // For non-GitHub remotes (GitLab, Bitbucket, etc.), return the full URL
   910→      return url;
   911→    } catch {
   912→      return undefined;
   913→    }
   914→  }
