   916→  private async validateLocalPath(localPath: string): Promise<void> {
   917→    if (!isAbsolute(localPath)) {
   918→      throw new Error(`localPath must be absolute: "${localPath}"`);
   919→    }
   920→    const s = await stat(localPath).catch(() => null);
   921→    if (!s?.isDirectory()) {
   922→      throw new Error(`localPath is not a directory: "${localPath}"`);
   923→    }
   924→  }
