   926→  private async enrichRepos(repos: FleetRepo[]): Promise<FleetRepo[]> {
   927→    return Promise.all(
   928→      repos.map(async (repo) => {
   929→        await this.validateLocalPath(repo.localPath);
   930→        if (repo.remote) return repo;
   931→        const remote = await this.resolveRemote(repo.localPath);
   932→        return remote ? { ...repo, remote } : repo;
   933→      }),
   934→    );
   935→  }
