   995→  private async executeRequestsSequentially(
   996→    fleetId: string,
   997→    bridgeId: string,
   998→    requests: BridgeRequest[],
   999→  ): Promise<void> {
  1000→    const fleets = await this.loadFleets();
  1001→    const fleet = fleets.find((f) => f.id === fleetId);
  1002→    const fleetRepos = fleet?.repos ?? [];
  1003→    const repoRemotes = fleetRepos
  1004→      .map((r) => r.remote)
  1005→      .filter((r): r is string => r !== undefined);
  1006→
  1007→    // Pre-load ship rules for sortie requests
  1008→    const sharedRules = await this.loadRules(fleet?.sharedRulePaths ?? []);
  1009→    const shipRules = await this.loadRules(fleet?.shipRulePaths ?? []);
  1010→    const shipExtraPrompt = [sharedRules, shipRules].filter(Boolean).join("\n\n") || undefined;
  1011→
  1012→    const results: string[] = [];
  1013→
  1014→    for (const request of requests) {
  1015→      try {
  1016→        const result = await this.requestHandler.handle(
  1017→          fleetId,
  1018→          request,
  1019→          fleetRepos,
  1020→          repoRemotes,
  1021→          fleet?.skillSources,
  1022→          shipExtraPrompt,
  1023→          fleet?.maxConcurrentSorties,
  1024→        );
  1025→        results.push(result);
  1026→
  1027→        const resultMessage = {
  1028→          type: "system" as const,
  1029→          subtype: "request-result" as const,
  1030→          content: result,
  1031→        };
  1032→        this.bridgeManager.addToHistory(fleetId, resultMessage);
  1033→        this.broadcast({
  1034→          type: "bridge:stream",
  1035→          data: { fleetId, message: resultMessage },
  1036→        });
  1037→      } catch (err) {
  1038→        const errorResult = `[Request Error] ${err instanceof Error ? err.message : String(err)}`;
  1039→        results.push(errorResult);
  1040→
  1041→        const errorMessage = {
  1042→          type: "system" as const,
  1043→          subtype: "request-result" as const,
  1044→          content: errorResult,
  1045→        };
  1046→        this.bridgeManager.addToHistory(fleetId, errorMessage);
  1047→        this.broadcast({
  1048→          type: "bridge:stream",
  1049→          data: { fleetId, message: errorMessage },
  1050→        });
  1051→      }
  1052→    }
  1053→
  1054→    // Send batched results to Bridge stdin
  1055→    this.processManager.sendMessage(bridgeId, results.join("\n\n"));
  1056→  }
