  1058→  private async executeShipRequests(
  1059→    shipId: string,
  1060→    requests: ShipRequest[],
  1061→  ): Promise<void> {
  1062→    const ship = this.shipManager.getShip(shipId);
  1063→    if (!ship) return;
  1064→
  1065→    // Load fleet gate settings for this ship
  1066→    const fleets = await this.loadFleets();
  1067→    const fleet = fleets.find((f) => f.id === ship.fleetId);
  1068→
  1069→    for (const request of requests) {
  1070→      const response: StatusTransitionResult = await this.shipRequestHandler.handle(shipId, request, fleet?.gates);
  1071→
  1072→      if (response.gate) {
  1073→        // Gate check required — initiate gate flow instead of writing response
  1074→        const planCommentUrl = request.request === "status-transition" ? request.planCommentUrl : undefined;
  1075→        await this.initiateGateCheck(shipId, response.gate.type, response.gate.from, response.gate.to, planCommentUrl, response.gate.previousFeedback);
  1076→        // Write a "pending" response so Ship knows to wait
  1077→        await ShipRequestHandler.writeResponse(ship.worktreePath, {
  1078→          ok: false,
  1079→          error: `Gate check initiated for ${response.gate.from} → ${response.gate.to}. Wait for gate-response.json.`,
  1080→        });
  1081→        console.log(
  1082→          `[ws-server] Ship ${shipId.slice(0, 8)}... gate check initiated: ${response.gate.from} → ${response.gate.to} (${response.gate.type})`,
  1083→        );
  1084→      } else {
  1085→        // Write response file so Ship CLI can poll for the result
  1086→        await ShipRequestHandler.writeResponse(ship.worktreePath, response);
  1087→
  1088→        if (response.ok) {
  1089→          console.log(
  1090→            `[ws-server] Ship ${shipId.slice(0, 8)}... request ${request.request} succeeded`,
  1091→          );
  1092→        } else {
  1093→          console.warn(
  1094→            `[ws-server] Ship ${shipId.slice(0, 8)}... request ${request.request} failed: ${response.error}`,
  1095→          );
  1096→        }
  1097→      }
  1098→    }
  1099→  }
  1100→
  1101→  private async initiateGateCheck(
  1102→    shipId: string,
  1103→    gateType: GateType,
  1104→    from: ShipStatus,
  1105→    to: ShipStatus,
  1106→    planCommentUrl?: string,
  1107→    previousFeedback?: string,
  1108→  ): Promise<void> {
  1109→    const ship = this.shipManager.getShip(shipId);
  1110→    if (!ship) return;
  1111→
  1112→    const transition = `${from}→${to}` as GateTransition;
  1113→
  1114→    // Dedup guard: skip if a pending gate already exists for this transition
  1115→    if (ship.gateCheck?.transition === transition && ship.gateCheck.status === "pending") {
  1116→      console.log(`[ws-server] Ship ${shipId.slice(0, 8)}... gate check already pending: ${transition} — skipping duplicate`);
  1117→      return;
  1118→    }
  1119→
  1120→    // For code-review gates, ensure PR URL is available.
  1121→    // If detectPRCreation() hasn't captured it yet, fall back to `gh pr list`.
  1122→    if (gateType === "code-review" && !ship.prUrl && ship.branchName) {
  1123→      try {
  1124→        const { stdout } = await execFileAsync("gh", [
  1125→          "pr", "list",
  1126→          "--head", ship.branchName,
  1127→          "--repo", ship.repo,
  1128→          "--json", "number,url",
  1129→          "--jq", ".[0]",
  1130→        ]);
  1131→        const trimmed = stdout.trim();
  1132→        if (trimmed) {
  1133→          const pr = JSON.parse(trimmed) as { number: number; url: string };
  1134→          ship.prUrl = pr.url;
  1135→          ship.prReviewStatus = "pending";
  1136→          console.log(
  1137→            `[ws-server] Ship ${shipId.slice(0, 8)}... PR URL resolved via fallback: ${pr.url}`,
  1138→          );
  1139→        }
  1140→      } catch {
  1141→        // gh pr list failed — proceed with "not yet created"
  1142→      }
  1143→    }
  1144→
  1145→
  1146→    // Set gate check state on the ship
  1147→    this.shipManager.setGateCheck(shipId, transition, gateType);
  1148→
  1149→    // Write gate-request.json for Ship to detect
  1150→    const gateRequest: GateFileRequest = {
  1151→      transition,
  1152→      gateType,
  1153→      message: `Gate check required: ${transition} (${gateType})`,
  1154→    };
  1155→    const claudeDir = join(ship.worktreePath, ".claude");
  1156→    mkdir(claudeDir, { recursive: true })
  1157→      .then(() => writeFile(join(claudeDir, "gate-request.json"), JSON.stringify(gateRequest, null, 2)))
  1158→      .catch((err) => console.error(`[ws-server] Failed to write gate-request.json:`, err));
  1159→
  1160→    // Notify frontend
  1161→    this.broadcast({
  1162→      type: "ship:gate-pending",
  1163→      data: {
  1164→        id: shipId,
  1165→        transition,
  1166→        gateType,
  1167→        fleetId: ship.fleetId,
  1168→        issueNumber: ship.issueNumber,
  1169→        issueTitle: ship.issueTitle,
  1170→      },
  1171→    });
  1172→
  1173→    // Build gate check message for Bridge
  1174→    const gateMessage = this.buildGateCheckMessage(ship, transition, gateType, planCommentUrl, previousFeedback);
  1175→
  1176→    // Inject into Bridge chat
  1177→    const bridgeMsg = {
  1178→      type: "system" as const,
  1179→      subtype: "gate-check-request" as const,
  1180→      content: gateMessage,
  1181→      meta: {
  1182→        category: "gate-check-request" as const,
  1183→        issueNumber: ship.issueNumber,
  1184→        issueTitle: ship.issueTitle,
  1185→        transition,
  1186→        gateType,
  1187→      },
  1188→    };
  1189→    this.bridgeManager.addToHistory(ship.fleetId, bridgeMsg);
  1190→    this.broadcast({
  1191→      type: "bridge:stream",
  1192→      data: { fleetId: ship.fleetId, message: bridgeMsg },
  1193→    });
  1194→
  1195→    // Send to Bridge stdin
  1196→    const bridgeId = `bridge-${ship.fleetId}`;
  1197→    this.processManager.sendMessage(bridgeId, gateMessage);
  1198→  }
  1199→
  1200→  private buildGateCheckMessage(
  1201→    ship: ShipProcess,
  1202→    transition: GateTransition,
  1203→    gateType: GateType,
  1204→    planCommentUrl?: string,
  1205→    previousFeedback?: string,
  1206→  ): string {
  1207→    const header = `[Gate Check Request] Ship #${ship.issueNumber} (${ship.issueTitle}): ${transition}`;
  1208→    const meta = `Ship ID: ${ship.id}\nRepo: ${ship.repo}\nGate type: ${gateType}\nWorktree: ${ship.worktreePath}\nShip log: ${ship.worktreePath}/.claude/ship-log.jsonl`;
  1209→    const retryNote = previousFeedback
  1210→      ? `\n\n⚠️ RETRY: This is a re-review after a previous rejection. The Ship claims to have addressed the following feedback:\n> ${previousFeedback}\nVerify that the previous issues have been fixed. Check GitHub (issue comments or PR reviews) for the full history of prior reviews.`
  1211→      : "";
  1212→
  1213→    switch (gateType) {
  1214→      case "plan-review": {
  1215→        const planRef = planCommentUrl
  1216→          ? `\nPlan comment: ${planCommentUrl}`
  1217→          : "";
  1218→        return `${header}\n${meta}${planRef}${retryNote}\n\nLaunch a Dispatch (sub-agent) to review the plan. Do NOT judge the gate yourself. The Dispatch must record on GitHub and output the gate-result admiral-request block.`;
  1219→      }
  1220→      case "code-review":
