  1467→  private async loadRules(paths: string[]): Promise<string> {
  1468→    if (!paths || paths.length === 0) return "";
  1469→    const parts: string[] = [];
  1470→    for (const p of paths) {
  1471→      try {
  1472→        const content = await readFile(p, "utf-8");
