     9→/**
    10→ * Extended response that indicates whether a gate check was triggered.
    11→ * When `gate` is set, the caller should NOT write the response file immediately —
    12→ * instead, it should initiate the gate check flow and write the response later.
    13→ */
    14→export interface StatusTransitionResult extends AdmiralRequestResponse {
    15→  gate?: {
    16→    type: GateType;
    17→    from: ShipStatus;
    18→    to: ShipStatus;
    19→    /** Feedback from the previous rejected gate check (for retry awareness). */
    20→    previousFeedback?: string;
    21→  };
    22→}
    23→
    24→/**
    25→ * Handles admiral-request blocks from Ship processes.
    26→ *
    27→ * Supports:
    28→ * - `status-transition`: Transactional phase change —
    29→ *   validates the transition, checks for gate requirements,
    30→ *   updates GitHub label synchronously, and confirms the new status internally.
    31→ * - `nothing-to-do`: Ship determined there is no work to do —
    32→ *   posts a comment on the issue, closes it, and marks the Ship as done.
    33→ */
    34→export class ShipRequestHandler {
    35→  private shipManager: ShipManager;
    36→  private statusManager: StatusManager;
    37→
    38→  constructor(shipManager: ShipManager, statusManager: StatusManager) {
    39→    this.shipManager = shipManager;
    40→    this.statusManager = statusManager;
    41→  }
    42→
    43→  /**
    44→   * Handle a Ship request and return a response.
    45→   * For status-transition, returns StatusTransitionResult which may include gate info.
    46→   * Gate settings are passed per-call to avoid concurrency issues across fleets.
    47→   */
    48→  async handle(
    49→    shipId: string,
    50→    request: ShipRequest,
    51→    gateSettings?: FleetGateSettings,
    52→  ): Promise<StatusTransitionResult> {
    53→    switch (request.request) {
    54→      case "status-transition":
    55→        return this.handleStatusTransition(shipId, request.status, gateSettings);
    56→      case "nothing-to-do":
    57→        return this.handleNothingToDo(shipId, request.reason);
    58→    }
    59→  }
    60→
    61→  private async handleStatusTransition(
    62→    shipId: string,
    63→    targetStatus: ShipStatus,
    64→    gateSettings?: FleetGateSettings,
    65→  ): Promise<StatusTransitionResult> {
    66→    const ship = this.shipManager.getShip(shipId);
    67→    if (!ship) {
    68→      return { ok: false, error: `Ship ${shipId} not found` };
    69→    }
    70→
    71→    // Handle "done" specially — it's a terminal state, not a phase label
    72→    if (targetStatus === "done") {
    73→      this.shipManager.updateStatus(shipId, "done");
    74→      return { ok: true };
    75→    }
    76→
    77→    // Validate forward-only phase advancement
    78→    const phaseOrder: ShipStatus[] = [
    79→      "planning", "implementing", "acceptance-test", "merging",
    80→    ];
    81→    const currentIdx = phaseOrder.indexOf(ship.status);
    82→    const targetIdx = phaseOrder.indexOf(targetStatus);
    83→
    84→    if (targetIdx < 0) {
    85→      return { ok: false, error: `Invalid target status: ${targetStatus}` };
    86→    }
    87→    if (targetIdx <= currentIdx) {
    88→      return {
    89→        ok: false,
    90→        error: `Cannot go backward: ${ship.status} → ${targetStatus}`,
    91→      };
    92→    }
    93→
    94→    // Check for gate on direct transition (from current → target)
    95→    const gateType = resolveGate(ship.status, targetStatus, gateSettings);
    96→    if (gateType) {
    97→      // If there's already a pending/approved gate for this exact transition, check it
    98→      if (ship.gateCheck?.transition === `${ship.status}→${targetStatus}`) {
    99→        if (ship.gateCheck.status === "approved") {
   100→          // Gate was approved — proceed with the transition
   101→          this.shipManager.clearGateCheck(shipId);
   102→        } else if (ship.gateCheck.status === "pending") {
   103→          // Gate is still pending — reject with a message
   104→          return {
   105→            ok: false,
   106→            error: `Gate check pending for ${ship.status} → ${targetStatus}. Waiting for Bridge approval.`,
   107→          };
   108→        } else if (ship.gateCheck.status === "rejected") {
   109→          // Gate was rejected — Ship should have acted on the feedback
   110→          // Capture the previous feedback before clearing
   111→          const prevFeedback = ship.gateCheck.feedback;
   112→          // Clear the rejection and let them re-request
   113→          this.shipManager.clearGateCheck(shipId);
   114→          // Fall through to initiate a new gate check with previous context
   115→          return {
   116→            ok: false,
   117→            gate: { type: gateType, from: ship.status, to: targetStatus, previousFeedback: prevFeedback },
   118→            error: `Gate check required for ${ship.status} → ${targetStatus}. Initiating review.`,
   119→          };
   120→        }
   121→      } else {
   122→        // No gate check yet — initiate one
   123→        return {
   124→          ok: false,
   125→          gate: { type: gateType, from: ship.status, to: targetStatus },
   126→          error: `Gate check required for ${ship.status} → ${targetStatus}. Initiating review.`,
   127→        };
   128→      }
   129→    }
   130→
   131→    // Legacy gate: block advancement to merging until code-review gate approves
   132→    // (safety check when the implementing→acceptance-test gate is disabled)
   133→    const mergingIdx = phaseOrder.indexOf("merging");
   134→    if (targetIdx >= mergingIdx && ship.prReviewStatus !== "approved") {
   135→      const codeReviewGate = resolveGate("implementing", "acceptance-test", gateSettings);
   136→      if (!codeReviewGate) {
   137→        return {
   138→          ok: false,
   139→          error: `Cannot advance to ${targetStatus}: PR review not approved (current: ${ship.prReviewStatus ?? "none"})`,
   140→        };
   141→      }
   142→    }
   143→
   144→    // Legacy gate: block advancement past acceptance-test until QA approved
   145→    // (safety check when the acceptance-test→merging gate is disabled)
   146→    const acceptanceIdx = phaseOrder.indexOf("acceptance-test");
   147→    if (targetIdx > acceptanceIdx && !ship.acceptanceTestApproved) {
   148→      const acceptanceGate = resolveGate("acceptance-test", "merging", gateSettings);
   149→      if (!acceptanceGate) {
   150→        return {
   151→          ok: false,
   152→          error: `Cannot advance past acceptance-test: not yet approved`,
   153→        };
   154→      }
   155→    }
   156→
   157→    // Transactional: sync GitHub label FIRST, then update internal state
   158→    try {
   159→      await this.statusManager.syncPhaseLabel(
   160→        ship.repo,
   161→        ship.issueNumber,
   162→        targetStatus,
   163→      );
   164→    } catch (err) {
   165→      return {
   166→        ok: false,
   167→        error: `GitHub label sync failed: ${err instanceof Error ? err.message : String(err)}`,
   168→      };
   169→    }
   170→
   171→    // Label update succeeded — now confirm the status internally
   172→    this.shipManager.updateStatus(shipId, targetStatus);
   173→    return { ok: true };
   174→  }
   175→
   176→  /**
   177→   * Handle "nothing-to-do": Ship determined there is no work needed.
   178→   * Posts a comment on the issue, closes it, and marks the Ship as done.
   179→   */
   180→  private async handleNothingToDo(
   181→    shipId: string,
   182→    reason: string,
   183→  ): Promise<StatusTransitionResult> {
   184→    const ship = this.shipManager.getShip(shipId);
   185→    if (!ship) {
   186→      return { ok: false, error: `Ship ${shipId} not found` };
   187→    }
   188→
   189→    // Post a comment explaining why there's nothing to do
   190→    try {
   191→      await github.commentOnIssue(
   192→        ship.repo,
   193→        ship.issueNumber,
   194→        `## Nothing to do\n\n${reason}\n\nClosing this issue as the problem appears to be already resolved.\n\n🤖 Generated with [Claude Code](https://claude.com/claude-code)`,
   195→      );
   196→    } catch (err) {
   197→      console.warn(
   198→        `[ship-request-handler] Failed to comment on #${ship.issueNumber}:`,
   199→        err,
   200→      );
   201→    }
   202→
   203→    // Close the issue
   204→    try {
   205→      await github.closeIssue(ship.repo, ship.issueNumber);
   206→    } catch (err) {
   207→      console.warn(
   208→        `[ship-request-handler] Failed to close #${ship.issueNumber}:`,
   209→        err,
   210→      );
   211→    }
   212→
   213→    // Mark Ship as done with nothingToDo flag
   214→    this.shipManager.setNothingToDo(shipId, reason);
   215→    this.shipManager.updateStatus(shipId, "done");
   216→
   217→    return { ok: true };
   218→  }
   219→
   220→  /**
   221→   * Execute a transition that was previously gated and is now approved.
   222→   * Called by the gate result handler after Bridge approves.
   223→   */
   224→  async executeGatedTransition(
   225→    shipId: string,
   226→    targetStatus: ShipStatus,
   227→  ): Promise<AdmiralRequestResponse> {
   228→    const ship = this.shipManager.getShip(shipId);
   229→    if (!ship) {
   230→      return { ok: false, error: `Ship ${shipId} not found` };
   231→    }
   232→
   233→    // Transactional: sync GitHub label FIRST, then update internal state
   234→    try {
   235→      await this.statusManager.syncPhaseLabel(
   236→        ship.repo,
   237→        ship.issueNumber,
   238→        targetStatus,
   239→      );
   240→    } catch (err) {
   241→      return {
   242→        ok: false,
   243→        error: `GitHub label sync failed: ${err instanceof Error ? err.message : String(err)}`,
   244→      };
   245→    }
   246→
   247→    this.shipManager.updateStatus(shipId, targetStatus);
   248→    return { ok: true };
   249→  }
   250→
   251→  /**
   252→   * Write the response file so Ship can poll for the result.
   253→   */
   254→  static async writeResponse(
   255→    worktreePath: string,
   256→    response: AdmiralRequestResponse,
   257→  ): Promise<void> {
   258→    const claudeDir = join(worktreePath, ".claude");
   259→    await mkdir(claudeDir, { recursive: true });
   260→    await writeFile(
   261→      join(claudeDir, "admiral-request-response.json"),
   262→      JSON.stringify(response, null, 2),
   263→    );
   264→  }
   265→}
