     4→interface ContentBlock {
     5→  type: string;
     6→  id?: string;
     7→  text?: string;
     8→  name?: string;
     9→  input?: Record<string, unknown>;
    10→}
    11→
    12→/**
    13→ * Extract sessionId from a raw init message.
    14→ * Returns the sessionId string if this is an init message, null otherwise.
    15→ * Must be called BEFORE parseStreamMessage (which drops init messages).
    16→ */
    17→export function extractSessionId(
    18→  raw: Record<string, unknown>,
    19→): string | null {
    20→  if (raw.type !== "system") return null;
    21→  if (raw.subtype !== "init") return null;
    22→  const sessionId = raw.session_id as string | undefined;
    23→  return sessionId ?? null;
    24→}
    25→
    26→/**
    27→ * Transform raw Claude CLI stream-json output into a StreamMessage
    28→ * that the frontend can display.
    29→ *
    30→ * Returns null for messages that should be silently dropped (e.g. hooks, init).
    31→ */
    32→export function parseStreamMessage(
    33→  raw: Record<string, unknown>,
    34→): StreamMessage | null {
    35→  const type = raw.type as string | undefined;
    36→
    37→  switch (type) {
    38→    case "assistant": {
    39→      const msg = raw.message as
    40→        | { content?: ContentBlock[] }
    41→        | undefined;
    42→      const blocks = msg?.content ?? [];
    43→
    44→      // Extract text blocks
    45→      const texts = blocks
    46→        .filter((b) => b.type === "text" && b.text)
    47→        .map((b) => b.text as string);
    48→
    49→      // Extract tool_use blocks
    50→      const toolUses = blocks.filter((b) => b.type === "tool_use");
    51→
    52→      if (texts.length > 0) {
    53→        return {
    54→          type: "assistant",
    55→          content: texts.join("\n"),
    56→        };
    57→      }
    58→
    59→      if (toolUses.length > 0) {
    60→        const toolName = toolUses[0]?.name ?? "tool";
    61→        const toolInput = toolUses[0]?.input;
    62→        const toolUseId = toolUses[0]?.id;
    63→        return {
    64→          type: "tool_use",
    65→          tool: toolName,
    66→          content: toolInput
    67→            ? JSON.stringify(toolInput, null, 2)
    68→            : toolName,
    69→          ...(toolInput ? { toolInput } : {}),
    70→          ...(toolUseId ? { toolUseId } : {}),
    71→        };
    72→      }
    73→
    74→      // Assistant message with no text and no tool_use — skip
    75→      return null;
    76→    }
    77→
    78→    case "result": {
    79→      const result = raw.result as string | undefined;
    80→      if (!result) return null;
    81→      return {
    82→        type: "result",
    83→        content: result,
    84→      };
    85→    }
    86→
    87→    case "system": {
    88→      const subtype = raw.subtype as string | undefined;
    89→      // Skip hooks, init, and task_notification — not useful for the user.
    90→      // Task results are already shown via TaskOutput tool_result messages.
    91→      // If a task_notification contains a description, surface it as a compact card.
    92→      if (subtype === "init" || subtype?.startsWith("hook")) {
    93→        return null;
    94→      }
    95→      if (subtype === "task_notification") {
    96→        const desc = (raw.description as string | undefined) ?? (raw.content as string | undefined);
    97→        if (!desc) return null;
    98→        return {
    99→          type: "system",
   100→          subtype: "task-notification" as StreamMessageSubtype,
   101→          content: desc,
   102→        };
   103→      }
   104→      // Compact status: { type: "system", subtype: "status", status: "compacting" | null }
   105→      if (subtype === "status") {
   106→        const status = raw.status as string | null | undefined;
   107→        if (status === "compacting" || status === null || status === undefined) {
   108→          return {
   109→            type: "system",
   110→            subtype: "compact-status",
   111→            content: status === "compacting" ? "Compacting context..." : "Context compaction complete",
   112→          };
   113→        }
   114→        // Non-compact status messages — fall through to generic handler
   115→      }
   116→      // Compact boundary: { type: "system", subtype: "compact_boundary", compact_metadata: {...} }
   117→      if (subtype === "compact_boundary") {
   118→        const metadata = raw.compact_metadata as { trigger?: string; pre_tokens?: number } | undefined;
   119→        const trigger = metadata?.trigger ?? "auto";
   120→        const preTokens = metadata?.pre_tokens;
   121→        const detail = preTokens
   122→          ? `Context compacted (${trigger}, ${preTokens.toLocaleString()} tokens before)`
   123→          : `Context compacted (${trigger})`;
   124→        return {
   125→          type: "system",
   126→          subtype: "compact-status",
   127→          content: detail,
   128→        };
   129→      }
   130→      return {
   131→        type: "system",
   132→        subtype: subtype as StreamMessageSubtype | undefined,
   133→        content: (raw.content as string) ?? subtype ?? "system",
   134→      };
   135→    }
   136→
   137→    case "tool_result": {
   138→      const rawContent = raw.content;
   139→      let content: string | undefined;
   140→      if (typeof rawContent === "string") {
   141→        content = rawContent;
   142→      } else if (Array.isArray(rawContent)) {
   143→        content = (rawContent as ContentBlock[])
   144→          .filter((b) => b.type === "text" && b.text)
   145→          .map((b) => b.text as string)
   146→          .join("\n");
   147→      }
   148→      if (!content) return null;
   149→      return {
   150→        type: "tool_result",
   151→        content,
   152→      };
   153→    }
   154→
   155→    default:
   156→      return null;
   157→  }
   158→}
   159→
   160→// === admiral-request protocol ===
   161→
   162→const REQUEST_BLOCK_RE = /```admiral-request\n([\s\S]*?)```/g;
   163→const REPO_PATTERN_REQ = /^[a-zA-Z0-9._-]+\/[a-zA-Z0-9._-]+$/;
   164→
   165→/** Valid statuses that Ship can request via status-transition. */
   166→const TRANSITION_TARGETS: ReadonlySet<ShipStatus> = new Set([
   167→  "planning",
   168→  "implementing",
   169→  "acceptance-test",
   170→  "merging",
   171→  "done",
   172→]);
   173→
   174→function validateRequest(obj: unknown): AdmiralRequest | null {
   175→  if (typeof obj !== "object" || obj === null) return null;
   176→  const r = obj as Record<string, unknown>;
   177→  const req = r.request;
   178→  if (typeof req !== "string") return null;
   179→
   180→  switch (req) {
   181→    case "ship-status":
   182→      return { request: "ship-status" };
   183→
   184→    case "ship-stop":
   185→      if (typeof r.shipId !== "string" || !r.shipId) return null;
   186→      return { request: "ship-stop", shipId: r.shipId };
   187→
   188→    case "sortie": {
   189→      if (!Array.isArray(r.items) || r.items.length === 0) return null;
   190→      const items: Array<{ repo: string; issueNumber: number; skill?: string }> = [];
   191→      for (const item of r.items) {
   192→        if (typeof item !== "object" || item === null) return null;
   193→        const it = item as Record<string, unknown>;
   194→        if (typeof it.repo !== "string" || !REPO_PATTERN_REQ.test(it.repo)) return null;
   195→        if (typeof it.issueNumber !== "number" || !Number.isInteger(it.issueNumber) || it.issueNumber <= 0) return null;
   196→        const entry: { repo: string; issueNumber: number; skill?: string } = {
   197→          repo: it.repo,
   198→          issueNumber: it.issueNumber,
   199→        };
   200→        if (typeof it.skill === "string") entry.skill = it.skill;
   201→        items.push(entry);
   202→      }
   203→      return { request: "sortie", items };
   204→    }
   205→
   206→    case "pr-review-result": {
   207→      if (typeof r.shipId !== "string" || !r.shipId) return null;
   208→      if (typeof r.prNumber !== "number" || !Number.isInteger(r.prNumber) || r.prNumber <= 0) return null;
   209→      if (r.verdict !== "approve" && r.verdict !== "request-changes") return null;
   210→      const result: { request: "pr-review-result"; shipId: string; prNumber: number; verdict: "approve" | "request-changes"; comments?: string } = {
   211→        request: "pr-review-result",
   212→        shipId: r.shipId,
   213→        prNumber: r.prNumber,
   214→        verdict: r.verdict,
   215→      };
   216→      if (typeof r.comments === "string") result.comments = r.comments;
   217→      return result;
   218→    }
   219→
   220→    case "gate-result": {
   221→      if (typeof r.shipId !== "string" || !r.shipId) return null;
   222→      if (typeof r.transition !== "string" || !GATE_TRANSITIONS.includes(r.transition as GateTransition)) return null;
   223→      if (r.verdict !== "approve" && r.verdict !== "reject") return null;
   224→      const gateResult: { request: "gate-result"; shipId: string; transition: GateTransition; verdict: "approve" | "reject"; feedback?: string; issueNumber?: number } = {
   225→        request: "gate-result",
   226→        shipId: r.shipId,
   227→        transition: r.transition as GateTransition,
   228→        verdict: r.verdict,
   229→      };
   230→      if (typeof r.feedback === "string") gateResult.feedback = r.feedback;
   231→      if (typeof r.issueNumber === "number") gateResult.issueNumber = r.issueNumber;
   232→      return gateResult;
   233→    }
   234→
   235→    case "gate-ack": {
   236→      if (typeof r.shipId !== "string" || !r.shipId) return null;
   237→      if (typeof r.transition !== "string" || !GATE_TRANSITIONS.includes(r.transition as GateTransition)) return null;
   238→      const gateAck: { request: "gate-ack"; shipId: string; transition: GateTransition; issueNumber?: number } = {
   239→        request: "gate-ack",
   240→        shipId: r.shipId,
   241→        transition: r.transition as GateTransition,
   242→      };
   243→      if (typeof r.issueNumber === "number") gateAck.issueNumber = r.issueNumber;
   244→      return gateAck;
   245→    }
   246→
   247→    case "status-transition": {
   248→      const status = r.status as string | undefined;
   249→      if (typeof status !== "string" || !TRANSITION_TARGETS.has(status as ShipStatus)) return null;
   250→      const transition: { request: "status-transition"; status: ShipStatus; planCommentUrl?: string } = {
   251→        request: "status-transition",
   252→        status: status as ShipStatus,
   253→      };
   254→      if (typeof r.planCommentUrl === "string") transition.planCommentUrl = r.planCommentUrl;
   255→      return transition;
   256→    }
   257→
   258→    case "nothing-to-do": {
   259→      if (typeof r.reason !== "string" || !r.reason) return null;
   260→      return { request: "nothing-to-do", reason: r.reason };
   261→    }
   262→
   263→    default:
   264→      return null;
   265→  }
   266→}
   267→
   268→/**
   269→ * Extract AdmiralRequest objects from ```admiral-request ... ``` fenced blocks.
   270→ * Returns both BridgeRequest and ShipRequest types — callers must filter by source.
   271→ */
   272→export function extractRequests(text: string): AdmiralRequest[] {
   273→  const requests: AdmiralRequest[] = [];
   274→  let match: RegExpExecArray | null;
   275→  while ((match = REQUEST_BLOCK_RE.exec(text)) !== null) {
   276→    try {
   277→      const parsed: unknown = JSON.parse(match[1]!);
   278→      const validated = validateRequest(parsed);
   279→      if (validated) requests.push(validated);
   280→    } catch {
   281→      console.warn("[stream-parser] Failed to parse admiral-request JSON");
   282→    }
   283→  }
   284→  REQUEST_BLOCK_RE.lastIndex = 0;
   285→  return requests;
   286→}
   287→
   288→const SHIP_REQUEST_TYPES = new Set(["status-transition", "nothing-to-do"]);
   289→
   290→/** Type guard: check if a request is a Bridge-only request. */
   291→export function isBridgeRequest(req: AdmiralRequest): req is BridgeRequest {
   292→  return !SHIP_REQUEST_TYPES.has(req.request);
   293→}
   294→
   295→/** Type guard: check if a request is a Ship request. */
   296→export function isShipRequest(req: AdmiralRequest): req is ShipRequest {
   297→  return SHIP_REQUEST_TYPES.has(req.request);
   298→}
   299→
   300→/**
   301→ * Remove ```admiral-request ... ``` blocks from text for display purposes.
   302→ */
   303→export function stripRequestBlocks(text: string): string {
   304→  return text.replace(REQUEST_BLOCK_RE, "").trim();
   305→}
