    10→export interface BridgeSession {
    11→  id: string;
    12→  fleetId: string;
    13→  fleetPath: string;
    14→  additionalDirs: string[];
    15→  systemPrompt?: string;
    16→  sessionId: string | null;
    17→  history: StreamMessage[];
    18→  /** Tool use ID of a pending AskUserQuestion (null when no question pending). */
    19→  pendingToolUseId: string | null;
    20→  /** Timestamp (ms epoch) when AskUserQuestion was received (null when no question pending). */
    21→  questionAskedAt: number | null;
    22→}
    23→
    24→export class BridgeManager {
    25→  private sessions = new Map<string, BridgeSession>();
    26→  private processManager: ProcessManager;
    27→  private appendCount = 0;
    28→
    29→  constructor(processManager: ProcessManager) {
    30→    this.processManager = processManager;
    31→  }
    32→
    33→  /**
    34→   * Launch a new Bridge session. If a persisted session exists with a valid
    35→   * sessionId, attempt to resume the Claude CLI session.
    36→   */
    37→  async launch(
    38→    fleetId: string,
    39→    fleetPath: string,
    40→    additionalDirs: string[],
    41→    systemPrompt?: string,
    42→  ): Promise<string> {
    43→    const bridgeId = `bridge-${fleetId}`;
    44→
    45→    // Load persisted history and session info
    46→    const restoredHistory = await this.loadHistory(fleetId);
    47→    const persisted = await this.loadSession(fleetId);
    48→
    49→    const session: BridgeSession = {
    50→      id: bridgeId,
    51→      fleetId,
    52→      fleetPath,
    53→      additionalDirs,
    54→      systemPrompt,
    55→      sessionId: persisted?.sessionId ?? null,
    56→      history: restoredHistory,
    57→      pendingToolUseId: null,
    58→      questionAskedAt: null,
    59→    };
    60→    this.sessions.set(fleetId, session);
    61→
    62→    if (session.sessionId) {
    63→      // Try to resume the existing Claude CLI session
    64→      this.processManager.resumeBridge(
    65→        bridgeId,
    66→        session.sessionId,
    67→        fleetPath,
    68→        additionalDirs,
    69→        systemPrompt,
    70→      );
    71→    } else {
    72→      this.processManager.launchBridge(
    73→        bridgeId,
    74→        fleetPath,
    75→        additionalDirs,
    76→        systemPrompt,
    77→      );
    78→    }
    79→    return bridgeId;
    80→  }
    81→
    82→  hasSession(fleetId: string): boolean {
    83→    return this.sessions.has(fleetId);
    84→  }
    85→
    86→  setSessionId(fleetId: string, sessionId: string): void {
    87→    const session = this.sessions.get(fleetId);
    88→    if (session && !session.sessionId) {
    89→      session.sessionId = sessionId;
    90→      this.persistSession(fleetId, sessionId);
    91→    }
    92→  }
    93→
    94→  send(
    95→    fleetId: string,
    96→    message: string,
    97→    images?: Array<{ base64: string; mediaType: string }>,
    98→  ): boolean {
    99→    const session = this.sessions.get(fleetId);
   100→    if (!session) return false;
   101→
   102→    const bridgeId = `bridge-${fleetId}`;
   103→
   104→    // Store user message in history (include image count, not full data, to limit memory)
   105→    const historyEntry: StreamMessage = { type: "user", content: message };
   106→    if (images && images.length > 0) {
   107→      historyEntry.imageCount = images.length;
   108→    }
   109→    this.addToHistory(fleetId, historyEntry);
   110→
   111→    // If process died, re-launch it
   112→    if (!this.processManager.isRunning(bridgeId)) {
   113→      if (session.sessionId) {
   114→        this.processManager.resumeBridge(
   115→          bridgeId,
   116→          session.sessionId,
   117→          session.fleetPath,
   118→          session.additionalDirs,
   119→          session.systemPrompt,
   120→        );
   121→      } else {
   122→        this.processManager.launchBridge(
   123→          bridgeId,
   124→          session.fleetPath,
   125→          session.additionalDirs,
   126→          session.systemPrompt,
   127→        );
   128→      }
   129→    }
   130→
   131→    // Send immediately — writing to stdin also unblocks Bun's pipe handling.
   132→    // Do NOT queue/defer: Bun blocks stdout when stdin pipe is idle,
   133→    // so waiting for init creates a deadlock (init never arrives).
   134→    this.processManager.sendMessage(bridgeId, message, images);
   135→    return true;
   136→  }
   137→
   138→  addToHistory(fleetId: string, message: StreamMessage): void {
   139→    const session = this.sessions.get(fleetId);
   140→    if (session) {
   141→      session.history.push(message);
   142→      if (session.history.length > MAX_HISTORY) {
   143→        session.history = session.history.slice(-MAX_HISTORY);
   144→      }
   145→      this.persistHistoryEntry(fleetId, message);
   146→    }
   147→  }
   148→
   149→  getHistory(fleetId: string): StreamMessage[] {
   150→    return this.sessions.get(fleetId)?.history ?? [];
   151→  }
   152→
   153→  setPendingQuestion(fleetId: string, toolUseId: string): void {
   154→    const session = this.sessions.get(fleetId);
   155→    if (session) {
   156→      session.pendingToolUseId = toolUseId;
   157→      session.questionAskedAt = Date.now();
   158→    }
   159→  }
   160→
   161→  clearPendingQuestion(fleetId: string): void {
   162→    const session = this.sessions.get(fleetId);
   163→    if (session) {
   164→      session.pendingToolUseId = null;
   165→      session.questionAskedAt = null;
   166→    }
   167→  }
   168→
   169→  getPendingQuestion(fleetId: string): { toolUseId: string; askedAt: number } | null {
   170→    const session = this.sessions.get(fleetId);
   171→    if (session?.pendingToolUseId && session.questionAskedAt) {
   172→      return { toolUseId: session.pendingToolUseId, askedAt: session.questionAskedAt };
   173→    }
   174→    return null;
   175→  }
   176→
   177→  /** Return all sessions that have a pending question. */
   178→  getSessionsWithPendingQuestion(): Array<{ fleetId: string; toolUseId: string; askedAt: number }> {
   179→    const results: Array<{ fleetId: string; toolUseId: string; askedAt: number }> = [];
   180→    for (const [fleetId, session] of this.sessions) {
