   252→          messages.push(JSON.parse(line) as StreamMessage);
   253→        } catch {
   254→          // Skip malformed lines
   255→        }
   256→      }
   257→      // Return only the last MAX_HISTORY entries
   258→      return messages.slice(-MAX_HISTORY);
   259→    } catch {
   260→      return [];
   261→    }
   262→  }
