import { randomUUID } from "node:crypto";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import { copyFile, mkdir, readFile, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { homedir } from "node:os";
import { ProcessManager } from "./process-manager.js";
import { AcceptanceWatcher } from "./acceptance-watcher.js";
import type { StatusManager } from "./status-manager.js";
import * as github from "./github.js";
import * as worktree from "./worktree.js";
import type { ShipProcess, ShipStatus, FleetSkillSources, PRReviewResponse, GateTransition, GateType, GateFileResponse, PersistedShip } from "./types.js";

const SHIPS_FILE = join(homedir(), ".vibe-admiral", "ships.json");

const execFileAsync = promisify(execFile);

export class ShipManager {
  private ships = new Map<string, ShipProcess>();
  private processManager: ProcessManager;
  private acceptanceWatcher: AcceptanceWatcher;
  private statusManager: StatusManager;
  private onStatusChange:
    | ((id: string, status: ShipStatus, detail?: string) => void)
    | null = null;

  constructor(
    processManager: ProcessManager,
    acceptanceWatcher: AcceptanceWatcher,
    statusManager: StatusManager,
  ) {
    this.processManager = processManager;
    this.acceptanceWatcher = acceptanceWatcher;
    this.statusManager = statusManager;
  }

  setStatusChangeHandler(
    handler: (id: string, status: ShipStatus, detail?: string) => void,
  ): void {
    this.onStatusChange = handler;
  }

  async sortie(
    fleetId: string,
    repo: string,
    issueNumber: number,
    localPath: string,
    skillSources?: FleetSkillSources,
    extraPrompt?: string,
    skill?: string,
  ): Promise<ShipProcess> {
    // Clean up all completed ships (done/error) on every new sortie
    for (const [id, ship] of this.ships) {
      if (ship.status === "done" || ship.status === "error") {
        this.ships.delete(id);
      }
    }

    const shipId = randomUUID();

    // 1. Get issue info (used later for title, slug, etc.)
    const issue = await github.getIssue(repo, issueNumber);

    // 2. Update issue status: todo → doing (via StatusManager)
    await this.statusManager.markDoing(repo, issueNumber);

    // 3. Create worktree
    const repoRoot = await worktree.getRepoRoot(localPath);
    const defaultBranch = await github.getDefaultBranch(repo);
    const slug = worktree.toKebabCase(issue.title);
    const branchName = `feature/${issueNumber}-${slug}`;
    const worktreePath = `${repoRoot}/.worktrees/feature/${issueNumber}-${slug}`;

    await worktree.create(worktreePath, branchName, defaultBranch);

    // 4. Symlink settings
    await worktree.symlinkSettings(repoRoot, worktreePath);

    // 5. Copy /implement skill to worktree
    await this.deploySkills(repoRoot, worktreePath, skillSources);

    // 6. npm install if web project
    if (await worktree.isWebProject(worktreePath)) {
      await execFileAsync("npm", ["install"], { cwd: worktreePath });
    }

    const ship: ShipProcess = {
      id: shipId,
      fleetId,
      repo,
      issueNumber,
      issueTitle: issue.title,
      status: "planning",
      isCompacting: false,
      branchName,
      worktreePath,
      sessionId: null,
      prUrl: null,
      prReviewStatus: null,
      acceptanceTest: null,
      acceptanceTestApproved: false,
      gateCheck: null,
      errorType: null,
      retryCount: 0,
      createdAt: new Date().toISOString(),
      lastOutputAt: null,
    };
    this.ships.set(shipId, ship);

    // 7. Launch Claude CLI process
    this.processManager.sortie(shipId, worktreePath, issueNumber, extraPrompt, skill);

    // 8. Start acceptance test watcher
    this.acceptanceWatcher.watch(worktreePath, shipId);

    this.updateStatus(shipId, "planning");
    return ship;
  }

  stopShip(shipId: string): boolean {
    const killed = this.processManager.kill(shipId);
    if (killed) {
      this.acceptanceWatcher.unwatch(shipId);
      const ship = this.ships.get(shipId);
      if (ship) ship.isCompacting = false;
      this.updateStatus(shipId, "error", "Manually stopped");
    }
    return killed;
  }

  getShip(shipId: string): ShipProcess | undefined {
    return this.ships.get(shipId);
  }

  /**
   * Resolve a Ship by: exact UUID → prefix match → issueNumber fallback.
   * Returns undefined if no match or if a prefix matches multiple ships.
   */
  resolveShip(shipId: string, issueNumber?: number): ShipProcess | undefined {
    // 1. Exact match
    const exact = this.ships.get(shipId);
    if (exact) return exact;

    // 2. Prefix match (only if shipId is shorter than a full UUID)
    if (shipId.length < 36) {
      const prefixMatches: ShipProcess[] = [];
      for (const ship of this.ships.values()) {
        if (ship.id.startsWith(shipId)) {
          prefixMatches.push(ship);
        }
      }
      if (prefixMatches.length === 1) return prefixMatches[0];
    }

    // 3. issueNumber fallback (active ships only)
    if (issueNumber !== undefined) {
      for (const ship of this.ships.values()) {
        if (ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
          return ship;
        }
      }
    }

    return undefined;
  }

  getShipsByFleet(fleetId: string): ShipProcess[] {
    return Array.from(this.ships.values()).filter(
      (s) => s.fleetId === fleetId,
    );
  }

  getAllShips(): ShipProcess[] {
    return Array.from(this.ships.values());
  }

  getShipByIssue(repo: string, issueNumber: number): ShipProcess | undefined {
    for (const ship of this.ships.values()) {
      if (ship.repo === repo && ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
        return ship;
      }
    }
    return undefined;
  }

  getActiveShipIssueNumbers(): Array<{ repo: string; issueNumber: number }> {
    const active: Array<{ repo: string; issueNumber: number }> = [];
    for (const ship of this.ships.values()) {
      if (ship.status !== "done" && ship.status !== "error") {
        active.push({ repo: ship.repo, issueNumber: ship.issueNumber });
      }
    }
    return active;
  }

  hasRunningProcess(shipId: string): boolean {
    return this.processManager.isRunning(shipId);
  }

  updateStatus(id: string, status: ShipStatus, detail?: string): void {
    const ship = this.ships.get(id);
    if (ship) {
      // Defensive: clear acceptanceTest when leaving acceptance-test status
      if (ship.status === "acceptance-test" && status !== "acceptance-test") {
        ship.acceptanceTest = null;
      }
      ship.status = status;
      if (status === "done" || status === "error") {
        ship.completedAt = Date.now();
      }
      // Note: GitHub label sync is now handled transactionally by ShipRequestHandler.
      // This method only updates in-memory state and notifies the frontend.
      this.onStatusChange?.(id, status, detail);
      this.persistToDisk();
    }
  }

  setNothingToDo(id: string, reason: string): void {
    const ship = this.ships.get(id);
    if (ship) {
      ship.nothingToDo = true;
      ship.nothingToDoReason = reason;
    }
  }

  async respondToPRReview(
    shipId: string,
    response: PRReviewResponse,
  ): Promise<void> {
    const ship = this.ships.get(shipId);
    if (!ship) return;

    ship.prReviewStatus = response.verdict === "approve" ? "approved" : "changes-requested";

    // On request-changes, revert phase to implementing so Ship can fix
    if (response.verdict === "request-changes") {
      this.updateStatus(shipId, "implementing");
    }

    // Ensure .claude directory exists and write response file for Ship CLI
    const claudeDir = join(ship.worktreePath, ".claude");
    await mkdir(claudeDir, { recursive: true });
    const responseFile = join(claudeDir, "pr-review-response.json");
    await writeFile(responseFile, JSON.stringify(response, null, 2));
  }

  setAcceptanceTest(
    shipId: string,
    request: { url: string; checks: string[] },
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.acceptanceTest = request;
  }

  clearAcceptanceTest(shipId: string): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.acceptanceTest = null;
  }

  respondToAcceptanceTest(
    shipId: string,
    accepted: boolean,
    feedback?: string,
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;

    if (accepted) {
      ship.acceptanceTestApproved = true;
    }

    this.acceptanceWatcher
      .respond(ship.worktreePath, { accepted, feedback })
      .catch((err) => {
        console.error(
          `Failed to write acceptance test response for ${shipId}:`,
          err,
        );
      });
  }

  setGateCheck(
    shipId: string,
    transition: GateTransition,
    gateType: GateType,
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.gateCheck = {
      transition,
      gateType,
      status: "pending",
      requestedAt: new Date().toISOString(),
    };
  }

  clearGateCheck(shipId: string): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.gateCheck = null;
  }

  async respondToGate(
    shipId: string,
    approved: boolean,
    feedback?: string,
  ): Promise<void> {
    const ship = this.ships.get(shipId);
    if (!ship || !ship.gateCheck) return;

    ship.gateCheck.status = approved ? "approved" : "rejected";
    if (feedback) ship.gateCheck.feedback = feedback;

    // Write gate-response.json for Ship CLI to poll
    const claudeDir = join(ship.worktreePath, ".claude");
    await mkdir(claudeDir, { recursive: true });
    const response: GateFileResponse = { approved, feedback };
    await writeFile(
      join(claudeDir, "gate-response.json"),
      JSON.stringify(response, null, 2),
    );
  }

  private async deploySkills(
    repoRoot: string,
    worktreePath: string,
    skillSources?: FleetSkillSources,
  ): Promise<void> {
    // Copy /implement orchestrator + sub-skills from the main repo's skills/
    // The orchestrator is essential for Ship operation — failure is fatal.
    const implementSrc = skillSources?.implement
      ? join(skillSources.implement, "SKILL.md")
      : join(repoRoot, "skills", "implement", "SKILL.md");
    const implementDestDir = join(worktreePath, ".claude", "skills", "implement");
    await mkdir(implementDestDir, { recursive: true });
    await copyFile(implementSrc, join(implementDestDir, "SKILL.md"));

    // Deploy Ship sub-skills and shared skills from repo's skills/ (non-fatal individually)
    const repoSkills = [
      // Ship sub-skills
      "implement-setup",
      "implement-plan",
      "implement-code",
      "implement-review",
      "implement-merge",
      // Shared skills (Bridge/Ship common)
      "admiral-protocol",
      "read-issue",
      // Other repo skills
      "adr",
    ];
    for (const skillName of repoSkills) {
      const src = join(repoRoot, "skills", skillName, "SKILL.md");
      const destDir = join(worktreePath, ".claude", "skills", skillName);
      try {
        await mkdir(destDir, { recursive: true });
        await copyFile(src, join(destDir, "SKILL.md"));
      } catch {
        console.warn(`[ship-manager] Failed to deploy /${skillName} skill`);
      }
    }

    // Copy dev-shared skills if devSharedDir is configured
    const devSharedDir = skillSources?.devSharedDir;
    if (!devSharedDir) return;

    const devSharedSkills = ["review-pr", "second-opinion", "test", "refactor"];
    for (const skillName of devSharedSkills) {
      const src = join(devSharedDir, skillName, "SKILL.md");
      const destDir = join(worktreePath, ".claude", "skills", skillName);
      try {
        await mkdir(destDir, { recursive: true });
        await copyFile(src, join(destDir, "SKILL.md"));
      } catch {
        console.warn(`[ship-manager] Failed to deploy /${skillName} skill from dev-shared`);
      }
    }
  }

  /**
   * Remove completed/error Ships that have no running process.
   * Called during startup reconciliation to clear ghosts from previous runs.
   */
  purgeOrphanShips(): number {
    let purged = 0;
    for (const [id, ship] of this.ships) {
      if (
        (ship.status === "done" || ship.status === "error") &&
        !this.processManager.isRunning(id)
      ) {
        this.ships.delete(id);
        purged++;
      }
    }
    if (purged > 0) {
      console.log(`[ship-manager] Purged ${purged} orphan ship(s)`);
      this.persistToDisk();
    }
    return purged;
  }

  /**
   * Retry an errored Ship. If the Ship has a sessionId, resume the session.
   * Otherwise, re-sortie from scratch.
   * Returns the resumed/re-launched ShipProcess, or null if not retryable.
   */
  retryShip(
    shipId: string,
    extraPrompt?: string,
    skill?: string,
  ): ShipProcess | null {
    const ship = this.ships.get(shipId);
    if (!ship || ship.status !== "error") return null;

    ship.retryCount++;
    ship.errorType = null;

    if (ship.sessionId) {
      // Resume existing session
      this.processManager.resumeSession(
        shipId,
        ship.sessionId,
        "The previous session was interrupted. Continue from where you left off.",
        ship.worktreePath,
      );
      this.updateStatus(shipId, "implementing", "Resumed from session");
    } else {
      // No session to resume — re-sortie
      this.processManager.sortie(
        shipId,
        ship.worktreePath,
        ship.issueNumber,
        extraPrompt,
        skill,
      );
      this.updateStatus(shipId, "planning", "Re-sortied");
    }

    this.acceptanceWatcher.watch(ship.worktreePath, shipId);
    return ship;
  }

  stopAll(): void {
    for (const [id] of this.ships) {
      this.processManager.kill(id);
    }
    this.acceptanceWatcher.unwatchAll();
  }

  /**
   * Persist active ships to disk so reconcileOnStartup can identify
   * genuinely active ships after an Engine restart.
   * Only ships with non-terminal statuses are persisted.
   */
  private persistToDisk(): void {
    const active: PersistedShip[] = [];
    for (const ship of this.ships.values()) {
      if (ship.status !== "done" && ship.status !== "error") {
        active.push({
          id: ship.id,
          fleetId: ship.fleetId,
          repo: ship.repo,
          issueNumber: ship.issueNumber,
          issueTitle: ship.issueTitle,
          worktreePath: ship.worktreePath,
          branchName: ship.branchName,
          sessionId: ship.sessionId,
          status: ship.status,
          createdAt: ship.createdAt,
        });
      }
    }
    // Fire-and-forget: persistence is best-effort, don't block the caller
    const dir = join(homedir(), ".vibe-admiral");
    mkdir(dir, { recursive: true })
      .then(() => writeFile(SHIPS_FILE, JSON.stringify(active, null, 2)))
      .catch((err) => {
        console.warn("[ship-manager] Failed to persist ships to disk:", err);
      });
  }

  /**
   * Restore ships from disk persistence file.
   * Called during startup reconciliation to recover active ship data
   * that was lost when the Engine process restarted.
   * Restored ships are added to the in-memory Map so that
   * getActiveShipIssueNumbers() returns them during reconciliation.
   */
  async restoreFromDisk(): Promise<number> {
    try {
      const content = await readFile(SHIPS_FILE, "utf-8");
      const persisted = JSON.parse(content) as PersistedShip[];
      let restored = 0;
      for (const ps of persisted) {
        // Skip if a ship with this ID already exists in memory
        if (this.ships.has(ps.id)) continue;
        // Only restore ships that had active (non-terminal) statuses
        if (ps.status === "done" || ps.status === "error") continue;

        const ship: ShipProcess = {
          id: ps.id,
          fleetId: ps.fleetId,
          repo: ps.repo,
          issueNumber: ps.issueNumber,
          issueTitle: ps.issueTitle,
          worktreePath: ps.worktreePath,
          branchName: ps.branchName,
          sessionId: ps.sessionId,
          status: ps.status,
          isCompacting: false,
          prUrl: null,
          prReviewStatus: null,
          acceptanceTest: null,
          acceptanceTestApproved: false,
          gateCheck: null,
          errorType: null,
          retryCount: 0,
          createdAt: ps.createdAt,
          lastOutputAt: null,
        };
        this.ships.set(ps.id, ship);
        restored++;
      }
      if (restored > 0) {
        console.log(`[ship-manager] Restored ${restored} ship(s) from disk`);
      }
      return restored;
    } catch {
      // File doesn't exist or is invalid — normal on first run
      return 0;
    }
  }
}

import { randomUUID } from "node:crypto";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import { copyFile, mkdir, readFile, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { homedir } from "node:os";
import { ProcessManager } from "./process-manager.js";
import { AcceptanceWatcher } from "./acceptance-watcher.js";
import type { StatusManager } from "./status-manager.js";
import * as github from "./github.js";
import * as worktree from "./worktree.js";
import type { ShipProcess, ShipStatus, FleetSkillSources, PRReviewResponse, GateTransition, GateType, GateFileResponse, PersistedShip } from "./types.js";

const SHIPS_FILE = join(homedir(), ".vibe-admiral", "ships.json");

const execFileAsync = promisify(execFile);

export class ShipManager {
  private ships = new Map<string, ShipProcess>();
  private processManager: ProcessManager;
  private acceptanceWatcher: AcceptanceWatcher;
  private statusManager: StatusManager;
  private onStatusChange:
    | ((id: string, status: ShipStatus, detail?: string) => void)
    | null = null;

  constructor(
    processManager: ProcessManager,
    acceptanceWatcher: AcceptanceWatcher,
    statusManager: StatusManager,
  ) {
    this.processManager = processManager;
    this.acceptanceWatcher = acceptanceWatcher;
    this.statusManager = statusManager;
  }

  setStatusChangeHandler(
    handler: (id: string, status: ShipStatus, detail?: string) => void,
  ): void {
    this.onStatusChange = handler;
  }

  async sortie(
    fleetId: string,
    repo: string,
    issueNumber: number,
    localPath: string,
    skillSources?: FleetSkillSources,
    extraPrompt?: string,
    skill?: string,
  ): Promise<ShipProcess> {
    // Clean up all completed ships (done/error) on every new sortie
    for (const [id, ship] of this.ships) {
      if (ship.status === "done" || ship.status === "error") {
        this.ships.delete(id);
      }
    }

    const shipId = randomUUID();

    // 1. Get issue info (used later for title, slug, etc.)
    const issue = await github.getIssue(repo, issueNumber);

    // 2. Update issue status: todo → doing (via StatusManager)
    await this.statusManager.markDoing(repo, issueNumber);

    // 3. Create worktree
    const repoRoot = await worktree.getRepoRoot(localPath);
    const defaultBranch = await github.getDefaultBranch(repo);
    const slug = worktree.toKebabCase(issue.title);
    const branchName = `feature/${issueNumber}-${slug}`;
    const worktreePath = `${repoRoot}/.worktrees/feature/${issueNumber}-${slug}`;

    await worktree.create(worktreePath, branchName, defaultBranch);

    // 4. Symlink settings
    await worktree.symlinkSettings(repoRoot, worktreePath);

    // 5. Copy /implement skill to worktree
    await this.deploySkills(repoRoot, worktreePath, skillSources);

    // 6. npm install if web project
    if (await worktree.isWebProject(worktreePath)) {
      await execFileAsync("npm", ["install"], { cwd: worktreePath });
    }

    const ship: ShipProcess = {
      id: shipId,
      fleetId,
      repo,
      issueNumber,
      issueTitle: issue.title,
      status: "planning",
      isCompacting: false,
      branchName,
      worktreePath,
      sessionId: null,
      prUrl: null,
      prReviewStatus: null,
      acceptanceTest: null,
      acceptanceTestApproved: false,
      gateCheck: null,
      errorType: null,
      retryCount: 0,
      createdAt: new Date().toISOString(),
      lastOutputAt: null,
    };
    this.ships.set(shipId, ship);

    // 7. Launch Claude CLI process
    this.processManager.sortie(shipId, worktreePath, issueNumber, extraPrompt, skill);

    // 8. Start acceptance test watcher
    this.acceptanceWatcher.watch(worktreePath, shipId);

    this.updateStatus(shipId, "planning");
    return ship;
  }

  stopShip(shipId: string): boolean {
    const killed = this.processManager.kill(shipId);
    if (killed) {
      this.acceptanceWatcher.unwatch(shipId);
      const ship = this.ships.get(shipId);
      if (ship) ship.isCompacting = false;
      this.updateStatus(shipId, "error", "Manually stopped");
    }
    return killed;
  }

  getShip(shipId: string): ShipProcess | undefined {
    return this.ships.get(shipId);
  }

  /**
   * Resolve a Ship by: exact UUID → prefix match → issueNumber fallback.
   * Returns undefined if no match or if a prefix matches multiple ships.
   */
  resolveShip(shipId: string, issueNumber?: number): ShipProcess | undefined {
    // 1. Exact match
    const exact = this.ships.get(shipId);
    if (exact) return exact;

    // 2. Prefix match (only if shipId is shorter than a full UUID)
    if (shipId.length < 36) {
      const prefixMatches: ShipProcess[] = [];
      for (const ship of this.ships.values()) {
        if (ship.id.startsWith(shipId)) {
          prefixMatches.push(ship);
        }
      }
      if (prefixMatches.length === 1) return prefixMatches[0];
    }

    // 3. issueNumber fallback (active ships only)
    if (issueNumber !== undefined) {
      for (const ship of this.ships.values()) {
        if (ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
          return ship;
        }
      }
    }

    return undefined;
  }

  getShipsByFleet(fleetId: string): ShipProcess[] {
    return Array.from(this.ships.values()).filter(
      (s) => s.fleetId === fleetId,
    );
  }

  getAllShips(): ShipProcess[] {
    return Array.from(this.ships.values());
  }

  getShipByIssue(repo: string, issueNumber: number): ShipProcess | undefined {
    for (const ship of this.ships.values()) {
      if (ship.repo === repo && ship.issueNumber === issueNumber && ship.status !== "done" && ship.status !== "error") {
        return ship;
      }
    }
    return undefined;
  }

  getActiveShipIssueNumbers(): Array<{ repo: string; issueNumber: number }> {
    const active: Array<{ repo: string; issueNumber: number }> = [];
    for (const ship of this.ships.values()) {
      if (ship.status !== "done" && ship.status !== "error") {
        active.push({ repo: ship.repo, issueNumber: ship.issueNumber });
      }
    }
    return active;
  }

  hasRunningProcess(shipId: string): boolean {
    return this.processManager.isRunning(shipId);
  }

  updateStatus(id: string, status: ShipStatus, detail?: string): void {
    const ship = this.ships.get(id);
    if (ship) {
      // Defensive: clear acceptanceTest when leaving acceptance-test status
      if (ship.status === "acceptance-test" && status !== "acceptance-test") {
        ship.acceptanceTest = null;
      }
      ship.status = status;
      if (status === "done" || status === "error") {
        ship.completedAt = Date.now();
      }
      // Note: GitHub label sync is now handled transactionally by ShipRequestHandler.
      // This method only updates in-memory state and notifies the frontend.
      this.onStatusChange?.(id, status, detail);
      this.persistToDisk();
    }
  }

  setNothingToDo(id: string, reason: string): void {
    const ship = this.ships.get(id);
    if (ship) {
      ship.nothingToDo = true;
      ship.nothingToDoReason = reason;
    }
  }

  setAcceptanceTest(
    shipId: string,
    request: { url: string; checks: string[] },
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.acceptanceTest = request;
  }

  clearAcceptanceTest(shipId: string): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.acceptanceTest = null;
  }

  respondToAcceptanceTest(
    shipId: string,
    accepted: boolean,
    feedback?: string,
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;

    if (accepted) {
      ship.acceptanceTestApproved = true;
    }

    this.acceptanceWatcher
      .respond(ship.worktreePath, { accepted, feedback })
      .catch((err) => {
        console.error(
          `Failed to write acceptance test response for ${shipId}:`,
          err,
        );
      });
  }

  setGateCheck(
    shipId: string,
    transition: GateTransition,
    gateType: GateType,
  ): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.gateCheck = {
      transition,
      gateType,
      status: "pending",
      requestedAt: new Date().toISOString(),
    };
  }

  clearGateCheck(shipId: string): void {
    const ship = this.ships.get(shipId);
    if (!ship) return;
    ship.gateCheck = null;
  }

  async respondToGate(
    shipId: string,
    approved: boolean,
    feedback?: string,
  ): Promise<void> {
    const ship = this.ships.get(shipId);
    if (!ship || !ship.gateCheck) return;

    ship.gateCheck.status = approved ? "approved" : "rejected";
    if (feedback) ship.gateCheck.feedback = feedback;

    // Write gate-response.json for Ship CLI to poll
    const claudeDir = join(ship.worktreePath, ".claude");
    await mkdir(claudeDir, { recursive: true });
    const response: GateFileResponse = { approved, feedback };
    await writeFile(
      join(claudeDir, "gate-response.json"),
      JSON.stringify(response, null, 2),
    );
  }

  private async deploySkills(
    repoRoot: string,
    worktreePath: string,
    skillSources?: FleetSkillSources,
  ): Promise<void> {
    // Copy /implement orchestrator + sub-skills from the main repo's skills/
    // The orchestrator is essential for Ship operation — failure is fatal.
    const implementSrc = skillSources?.implement
      ? join(skillSources.implement, "SKILL.md")
      : join(repoRoot, "skills", "implement", "SKILL.md");
    const implementDestDir = join(worktreePath, ".claude", "skills", "implement");
    await mkdir(implementDestDir, { recursive: true });
    await copyFile(implementSrc, join(implementDestDir, "SKILL.md"));

    // Deploy Ship sub-skills and shared skills from repo's skills/ (non-fatal individually)
    const repoSkills = [
      // Ship sub-skills
      "implement-setup",
      "implement-plan",
      "implement-code",
      "implement-review",
      "implement-merge",
      // Shared skills (Bridge/Ship common)
      "admiral-protocol",
      "read-issue",
      // Other repo skills
      "adr",
    ];
    for (const skillName of repoSkills) {
      const src = join(repoRoot, "skills", skillName, "SKILL.md");
      const destDir = join(worktreePath, ".claude", "skills", skillName);
      try {
        await mkdir(destDir, { recursive: true });
        await copyFile(src, join(destDir, "SKILL.md"));
      } catch {
        console.warn(`[ship-manager] Failed to deploy /${skillName} skill`);
      }
    }

    // Copy dev-shared skills if devSharedDir is configured
    const devSharedDir = skillSources?.devSharedDir;
    if (!devSharedDir) return;

    const devSharedSkills = ["review-pr", "second-opinion", "test", "refactor"];
    for (const skillName of devSharedSkills) {
      const src = join(devSharedDir, skillName, "SKILL.md");
      const destDir = join(worktreePath, ".claude", "skills", skillName);
      try {
        await mkdir(destDir, { recursive: true });
        await copyFile(src, join(destDir, "SKILL.md"));
      } catch {
        console.warn(`[ship-manager] Failed to deploy /${skillName} skill from dev-shared`);
      }
    }
  }

  /**
   * Remove completed/error Ships that have no running process.
   * Called during startup reconciliation to clear ghosts from previous runs.
   */
  purgeOrphanShips(): number {
    let purged = 0;
    for (const [id, ship] of this.ships) {
      if (
        (ship.status === "done" || ship.status === "error") &&
        !this.processManager.isRunning(id)
      ) {
        this.ships.delete(id);
        purged++;
      }
    }
    if (purged > 0) {
      console.log(`[ship-manager] Purged ${purged} orphan ship(s)`);
      this.persistToDisk();
    }
    return purged;
  }

  /**
   * Retry an errored Ship. If the Ship has a sessionId, resume the session.
   * Otherwise, re-sortie from scratch.
   * Returns the resumed/re-launched ShipProcess, or null if not retryable.
   */
  retryShip(
    shipId: string,
    extraPrompt?: string,
    skill?: string,
  ): ShipProcess | null {
    const ship = this.ships.get(shipId);
    if (!ship || ship.status !== "error") return null;

    ship.retryCount++;
    ship.errorType = null;

    if (ship.sessionId) {
      // Resume existing session
      this.processManager.resumeSession(
        shipId,
        ship.sessionId,
        "The previous session was interrupted. Continue from where you left off.",
        ship.worktreePath,
      );
      this.updateStatus(shipId, "implementing", "Resumed from session");
    } else {
      // No session to resume — re-sortie
      this.processManager.sortie(
        shipId,
        ship.worktreePath,
        ship.issueNumber,
        extraPrompt,
        skill,
      );
      this.updateStatus(shipId, "planning", "Re-sortied");
    }

    this.acceptanceWatcher.watch(ship.worktreePath, shipId);
    return ship;
  }

  stopAll(): void {
    for (const [id] of this.ships) {
      this.processManager.kill(id);
    }
    this.acceptanceWatcher.unwatchAll();
  }

  /**
   * Persist active ships to disk so reconcileOnStartup can identify
   * genuinely active ships after an Engine restart.
   * Only ships with non-terminal statuses are persisted.
   */
  private persistToDisk(): void {
    const active: PersistedShip[] = [];
    for (const ship of this.ships.values()) {
      if (ship.status !== "done" && ship.status !== "error") {
        active.push({
          id: ship.id,
          fleetId: ship.fleetId,
          repo: ship.repo,
          issueNumber: ship.issueNumber,
          issueTitle: ship.issueTitle,
          worktreePath: ship.worktreePath,
          branchName: ship.branchName,
          sessionId: ship.sessionId,
          status: ship.status,
          createdAt: ship.createdAt,
        });
      }
    }
    // Fire-and-forget: persistence is best-effort, don't block the caller
    const dir = join(homedir(), ".vibe-admiral");
    mkdir(dir, { recursive: true })
      .then(() => writeFile(SHIPS_FILE, JSON.stringify(active, null, 2)))
      .catch((err) => {
        console.warn("[ship-manager] Failed to persist ships to disk:", err);
      });
  }

  /**
   * Restore ships from disk persistence file.
   * Called during startup reconciliation to recover active ship data
   * that was lost when the Engine process restarted.
   * Restored ships are added to the in-memory Map so that
   * getActiveShipIssueNumbers() returns them during reconciliation.
   */
  async restoreFromDisk(): Promise<number> {
    try {
      const content = await readFile(SHIPS_FILE, "utf-8");
      const persisted = JSON.parse(content) as PersistedShip[];
      let restored = 0;
      for (const ps of persisted) {
        // Skip if a ship with this ID already exists in memory
        if (this.ships.has(ps.id)) continue;
        // Only restore ships that had active (non-terminal) statuses
        if (ps.status === "done" || ps.status === "error") continue;

        const ship: ShipProcess = {
          id: ps.id,
          fleetId: ps.fleetId,
          repo: ps.repo,
          issueNumber: ps.issueNumber,
          issueTitle: ps.issueTitle,
          worktreePath: ps.worktreePath,
          branchName: ps.branchName,
          sessionId: ps.sessionId,
          status: ps.status,
          isCompacting: false,
          prUrl: null,
          prReviewStatus: null,
          acceptanceTest: null,
          acceptanceTestApproved: false,
          gateCheck: null,
          errorType: null,
          retryCount: 0,
          createdAt: ps.createdAt,
          lastOutputAt: null,
        };
        this.ships.set(ps.id, ship);
        restored++;
      }
      if (restored > 0) {
        console.log(`[ship-manager] Restored ${restored} ship(s) from disk`);
      }
      return restored;
    } catch {
      // File doesn't exist or is invalid — normal on first run
      return 0;
    }
  }
}

import type { ShipManager } from "./ship-manager.js";
import type { ShipRequestHandler } from "./ship-request-handler.js";
import type { StateSync } from "./state-sync.js";
import type { BridgeRequest, FleetRepo, FleetSkillSources, GateTransition, ShipProcess } from "./types.js";
import { parseTransition } from "./gate-config.js";

export class BridgeRequestHandler {
  private shipManager: ShipManager;
  private stateSync: StateSync;
  private shipRequestHandler: ShipRequestHandler | null = null;
  private onGateApproved:
    | ((shipId: string, transition: GateTransition) => void)
    | null = null;
  private onGateRejected:
    | ((shipId: string, transition: GateTransition, feedback?: string) => void)
    | null = null;

  constructor(shipManager: ShipManager, stateSync: StateSync) {
    this.shipManager = shipManager;
    this.stateSync = stateSync;
  }

  setShipRequestHandler(handler: ShipRequestHandler): void {
    this.shipRequestHandler = handler;
  }

  setGateApprovedHandler(
    handler: (shipId: string, transition: GateTransition) => void,
  ): void {
    this.onGateApproved = handler;
  }

  setGateRejectedHandler(
    handler: (shipId: string, transition: GateTransition, feedback?: string) => void,
  ): void {
    this.onGateRejected = handler;
  }

  async handle(
    fleetId: string,
    request: BridgeRequest,
    fleetRepos: FleetRepo[],
    repoRemotes: string[],
    skillSources?: FleetSkillSources,
    shipExtraPrompt?: string,
    maxConcurrentSorties?: number,
  ): Promise<string> {
    switch (request.request) {
      case "sortie":
        return this.handleSortie(fleetId, request, fleetRepos, repoRemotes, skillSources, shipExtraPrompt, maxConcurrentSorties);
      case "ship-status":
        return this.handleShipStatus(fleetId);
      case "ship-stop":
        return this.handleShipStop(request);
      case "pr-review-result":
        return this.handlePRReviewResult(request);
      case "gate-result":
        return this.handleGateResult(request);
      case "gate-ack":
        return this.handleGateAck(request);
    }
  }

  private async handleSortie(
    fleetId: string,
    request: Extract<BridgeRequest, { request: "sortie" }>,
    fleetRepos: FleetRepo[],
    repoRemotes: string[],
    skillSources?: FleetSkillSources,
    shipExtraPrompt?: string,
    maxConcurrentSorties?: number,
  ): Promise<string> {
    // Determine concurrent sortie limit (static, not dynamically adjusted)
    const configuredMax = maxConcurrentSorties ?? 6;
    const activeShips = this.shipManager.getShipsByFleet(fleetId)
      .filter((s: ShipProcess) => s.status !== "done" && s.status !== "error");
    const availableSlots = Math.max(0, configuredMax - activeShips.length);

    if (availableSlots === 0) {
      return `[Sortie Throttled] Concurrent limit reached (${activeShips.length}/${configuredMax} active). Wait for Ships to complete.`;
    }

    const repoSet = new Set(repoRemotes);
    const results: string[] = [];
    let launched = 0;

    for (const item of request.items) {
      // Check per-item concurrent limit
      if (launched >= availableSlots) {
        results.push(
          `Deferred ${item.repo}#${item.issueNumber}: concurrent limit reached (${configuredMax})`,
        );
        continue;
      }
      // Validate repo is in fleet whitelist
      if (!repoSet.has(item.repo)) {
        results.push(
          `Rejected ${item.repo}#${item.issueNumber}: repo not registered in this fleet`,
        );
        continue;
      }

      // Run sortie guard
      const guard = await this.stateSync.sortieGuard(item.repo, item.issueNumber);
      if (!guard.ok) {
        results.push(
          `Blocked ${item.repo}#${item.issueNumber}: ${guard.reason}`,
        );
        continue;
      }

      // Find local path
      const repoEntry = fleetRepos.find(
        (r) => r.remote === item.repo || r.localPath === item.repo,
      );
      if (!repoEntry) {
        results.push(
          `Failed ${item.repo}#${item.issueNumber}: no local path registered`,
        );
        continue;
      }

      try {
        const ship = await this.shipManager.sortie(
          fleetId,
          item.repo,
          item.issueNumber,
          repoEntry.localPath,
          skillSources,
          shipExtraPrompt,
          item.skill,
        );
        launched++;
        results.push(
          `Ship ${ship.id} launched for ${item.repo}#${item.issueNumber} (${ship.issueTitle})`,
        );
      } catch (err) {
        results.push(
          `Failed ${item.repo}#${item.issueNumber}: ${err instanceof Error ? err.message : String(err)}`,
        );
      }
    }

    return `[Sortie Results]\n${results.join("\n")}`;
  }

  private handleShipStatus(fleetId: string): string {
    const ships = this.shipManager.getShipsByFleet(fleetId);
    if (ships.length === 0) {
      return "[Ship Status] No active ships in this fleet.";
    }
    const lines = ships.map(
      (s) =>
        `  Ship ${s.id} #${s.issueNumber} (${s.issueTitle}): ${s.status}${s.gateCheck ? ` [gate: ${s.gateCheck.transition} ${s.gateCheck.status}]` : ""}\n    Worktree: ${s.worktreePath}\n    Log: ${s.worktreePath}/.claude/ship-log.jsonl`,
    );
    return `[Ship Status]\n${lines.join("\n")}`;
  }

  private handleShipStop(
    request: Extract<BridgeRequest, { request: "ship-stop" }>,
  ): string {
    const ship = this.shipManager.resolveShip(request.shipId);
    if (!ship) {
      return `[Stop Ship Failed] Ship ${request.shipId} not found or already stopped`;
    }
    const killed = this.shipManager.stopShip(ship.id);
    if (killed) {
      return `[Ship Stopped] ${ship.id}`;
    }
    return `[Stop Ship Failed] Ship ${request.shipId} not found or already stopped`;
  }

  private handlePRReviewResult(
    request: Extract<BridgeRequest, { request: "pr-review-result" }>,
  ): string {
    const ship = this.shipManager.resolveShip(request.shipId);
    if (!ship) {
      return `[PR Review Failed] Ship ${request.shipId} not found`;
    }

    this.shipManager.respondToPRReview(ship.id, {
      verdict: request.verdict,
      comments: request.comments,
    });

    const label = request.verdict === "approve" ? "APPROVED" : "CHANGES REQUESTED";
    return `[PR Review Result] Ship #${ship.issueNumber} PR #${request.prNumber}: ${label}${request.comments ? ` — ${request.comments}` : ""}`;
  }

  private handleGateAck(
    request: Extract<BridgeRequest, { request: "gate-ack" }>,
  ): string {
    const ship = this.shipManager.resolveShip(request.shipId, request.issueNumber);
    if (!ship) {
      return `[Gate ACK Failed] Ship ${request.shipId} not found`;
    }

    if (!ship.gateCheck || ship.gateCheck.transition !== request.transition) {
      return `[Gate ACK Failed] Ship #${ship.issueNumber} has no pending gate for ${request.transition}`;
    }

    if (ship.gateCheck.status !== "pending") {
      return `[Gate ACK Failed] Ship #${ship.issueNumber} gate for ${request.transition} is already ${ship.gateCheck.status}`;
    }

    ship.gateCheck.acknowledgedAt = new Date().toISOString();
    console.log(
      `[bridge-request] Gate ACK received for Ship #${ship.issueNumber}: ${request.transition} — timeout window reset`,
    );
    return `[Gate ACK] Ship #${ship.issueNumber}: ${request.transition} acknowledged — timeout window reset`;
  }

  private async handleGateResult(
    request: Extract<BridgeRequest, { request: "gate-result" }>,
  ): Promise<string> {
    const ship = this.shipManager.resolveShip(request.shipId, request.issueNumber);
    if (!ship) {
      return `[Gate Result Failed] Ship ${request.shipId} not found`;
    }

    if (!ship.gateCheck || ship.gateCheck.transition !== request.transition) {
      return `[Gate Result Failed] Ship #${ship.issueNumber} has no pending gate for ${request.transition}`;
    }

    if (ship.gateCheck.status !== "pending") {
      return `[Gate Result Failed] Ship #${ship.issueNumber} gate for ${request.transition} is already ${ship.gateCheck.status}`;
    }

    const approved = request.verdict === "approve";
    await this.shipManager.respondToGate(
      ship.id,
      approved,
      request.feedback,
    );

    if (approved) {
      // Execute the gated transition
      const { to } = parseTransition(request.transition);
      if (this.shipRequestHandler) {
        const result = await this.shipRequestHandler.executeGatedTransition(
          ship.id,
          to,
        );
        if (result.ok) {
          this.onGateApproved?.(ship.id, request.transition);
          return `[Gate Approved] Ship #${ship.issueNumber}: ${request.transition} — transition confirmed`;
        }
        return `[Gate Approved but Transition Failed] Ship #${ship.issueNumber}: ${result.error}`;
      }
      return `[Gate Approved] Ship #${ship.issueNumber}: ${request.transition}`;
    }

    this.onGateRejected?.(ship.id, request.transition, request.feedback);
    return `[Gate Rejected] Ship #${ship.issueNumber}: ${request.transition}${request.feedback ? ` — ${request.feedback}` : ""}`;
  }
}

